#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义三个变量，存储作业、小测和期末考试成绩
    // 因为成绩可能是小数，所以使用 double 类型
    double homework, quiz, exam;

    // 从键盘读入三个成绩
    cin >> homework >> quiz >> exam;

    // 按照公式计算总成绩
    // 作业成绩占20%，小测成绩占30%，期末考试成绩占50%
    double total = homework * 0.2 + quiz * 0.3 + exam * 0.5;

    // 输出总成绩
    // 如果结果是整数，会自动输出整数形式（如90）
    // 如果结果是小数，会输出小数形式（如86.8）
    cout << total << endl;

    return 0;
}

