#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义变量：y为起征金额，a为实际收入
    int y, a;
    cin >> y >> a;

    // 定义变量tax用于存储要交的税费
    double tax;

    // 判断收入是否超过起征点
    if (a > y) {
        // 超过部分 = 实际收入 - 起征金额
        double exceed = a - y;
        // 税费 = 超过部分 × 0.319 + 100.86
        tax = exceed * 0.319 + 100.86;
    } else {
        // 收入不超过起征点，不需要交税
        tax = 0;
    }

    // 输出结果，保留2位小数
    // fixed表示使用定点表示法，setprecision(2)设置小数位数为2
    cout << fixed << setprecision(2) << tax << endl;

    return 0;
}

