    double hours;

    // 输入小数形式的小时数
    cin >> hours;

    // 提取整数部分作为小时数
    // 例如 2.8 的小时部分是 2
    int hour_part = (int)hours;  // 强制类型转换，舍弃小数部分

    // 计算分钟数
    // 思路：小数部分 * 60 得到分钟数
    // 例如 2.8 的小数部分是 0.8，0.8 * 60 = 48 分钟
    // 注意：需要四舍五入处理，避免浮点数精度问题
    int minute_part = (int)((hours - hour_part) * 60 + 0.5);
    // 加上0.5再取整，实现四舍五入的效果

    // 输出结果，两个整数之间用空格隔开
    cout << hour_part << " " << minute_part << endl;

    return 0;
}

