#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义变量存储充值金额和实际到账金额
    int recharge;  // 充值金额
    int actual;    // 实际到账金额

    // 输入充值金额
    cin >> recharge;

    // 根据充值金额判断赠送规则
    // 使用if-else if-else多分支结构
    if (recharge < 200) {
        // 充值200元以下，没有赠送
        actual = recharge;
    } else if (recharge <= 299) {
        // 充值200元~299元，赠送50元
        actual = recharge + 50;
    } else if (recharge <= 499) {
        // 充值300元~499元，赠送100元
        actual = recharge + 100;
    } else {
        // 充值500元及以上，赠送200元
        actual = recharge + 200;
    }

    // 输出实际到账金额
    cout << actual << endl;

    return 0;
}

