    // 输入两个数
    cin >> a >> b;
    // 输入操作符
    cin >> op;

    // 使用switch语句根据不同的操作符进行分支处理
    switch (op) {
        case '+':
            // 加法运算，保留3位小数
            cout << fixed << setprecision(3) << a + b << endl;
            break;
        case '-':
            // 减法运算，保留3位小数
            cout << fixed << setprecision(3) << a - b << endl;
            break;
        case '*':
            // 乘法运算，保留3位小数
            cout << fixed << setprecision(3) << a * b << endl;
            break;
        case '/':
            // 除法运算前需要判断除数是否为0
            if (b == 0) {
                // 除数为0的情况
                cout << "Divided by zero" << endl;
            } else {
                // 正常除法运算，保留3位小数
                cout << fixed << setprecision(3) << a / b << endl;
            }
            break;
        default:
            // 如果操作符不是+、-、*、/中的任何一个
            cout << "Invalid operator" << endl;
            break;
    }

    return 0;
}

