    // 输入三位数
    cin >> x;

    // 分解三位数的各个数位
    // 百位：除以100取整
    a = x / 100;
    // 十位：先除以10取整，再对10取余
    b = x / 10 % 10;
    // 个位：对10取余
    c = x % 10;

    // 判断是否为水仙花数
    // 条件：各位数字的立方和等于原数
    if (a * a * a + b * b * b + c * c * c == x) {
        cout << "yes" << endl;
    } else {
        cout << "no" << endl;
    }

    return 0;
}

