        cout << "夏" << endl;
    }
    // 秋季：9~11月
    else if (m >= 9 && m <= 11) {
        cout << "秋" << endl;
    }
    // 冬季：12月、1月、2月
    // 注意：12月是上一年的最后一个月，1月和2月是下一年的前两个月
    else if (m == 12 || m == 1 || m == 2) {
        cout << "冬" << endl;
    }

    return 0;
}

