    // 定义三个布尔变量，分别记录能否被3、5、7整除
    bool div3 = (n % 3 == 0);  // 能被3整除
    bool div5 = (n % 5 == 0);  // 能被5整除
    bool div7 = (n % 7 == 0);  // 能被7整除

    // 统计能被几个数整除
    int count = 0;
    if (div3) count++;
    if (div5) count++;
    if (div7) count++;

    // 根据整除的个数进行判断
    if (count == 3) {
        // 能同时被3、5、7整除
        cout << "3 5 7" << endl;
    } else if (count == 2) {
        // 只能被其中两个数整除，小的在前，大的在后
        if (div3 && div5) {
            cout << "3 5" << endl;
        } else if (div3 && div7) {
            cout << "3 7" << endl;
        } else {  // div5 && div7
            cout << "5 7" << endl;
        }
    } else if (count == 1) {
        // 只能被其中一个数整除
        if (div3) {
            cout << "3" << endl;
        } else if (div5) {
            cout << "5" << endl;
        } else {  // div7
            cout << "7" << endl;
        }
    } else {
        // 不能被任何数整除
        cout << "n" << endl;
    }

    return 0;
}

