    // 定义变量n，用于存储输入的数字
    int n;

    // 输入一个整数n
    cin >> n;

    // 从n开始向下遍历到1
    // 因为要输出奇数，所以步长为2
    // 如果n是偶数，从n-1开始；如果n是奇数，从n开始
    for (int i = n; i >= 1; i--) {
        // 判断当前数是否为奇数
        if (i % 2 == 1) {
            // 如果是奇数，输出该数
            cout << i;

            // 如果不是最后一个数（即不是1），输出空格
            if (i > 1) {
                cout << " ";
            }
        }
    }

    // 输出换行
    cout << endl;

    return 0;
}

