int main() {
    // 定义变量
    int n;          // 数字的个数
    int num;        // 当前输入的数字
    int maxVal;     // 记录最大值

    // 输入数字个数
    cin >> n;

    // 先输入第一个数，作为最大值的初始值
    cin >> maxVal;

    // 用for循环处理剩下的n-1个数
    for (int i = 2; i <= n; i++) {
        cin >> num;         // 输入一个数
        if (num > maxVal) { // 如果当前数比最大值大
            maxVal = num;   // 更新最大值
        }
    }

    // 输出最大值
    cout << maxVal << endl;

    return 0;
}

