    // 定义变量n，用于存储输入的自然数
    int n;
    cin >> n;

    // 标记是否为质数，默认为是
    bool isPrime = true;

    // 质数判断：从2开始到n-1，检查是否有因子
    // 注意：n > 1，所以从2开始循环
    for (int i = 2; i < n; i++) {
        // 如果n能被i整除，说明n不是质数
        if (n % i == 0) {
            isPrime = false;
            break;  // 找到因子后立即退出循环，提高效率
        }
    }

    // 根据判断结果输出
    if (isPrime) {
        cout << "yes" << endl;
    } else {
        cout << "no" << endl;
    }

    return 0;
}

