#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义两个正整数 n 和 m
    int n, m;
    cin >> n >> m;

    // 方法：辗转相除法（欧几里得算法）
    // 原理：gcd(a, b) = gcd(b, a % b)，直到余数为0
    // 使用while循环实现，符合当前课次（循环结构）的要求

    // 保存原始的n和m，方便后续输出
    int a = n, b = m;

    // 当b不为0时，继续循环
    while (b != 0) {
        // 保存当前的余数
        int temp = a % b;
        // 将b赋值给a，将余数赋值给b
        a = b;
        b = temp;
    }

    // 循环结束后，a就是最大公约数
    cout << a << endl;

    return 0;
}

