int main() {
    // 读入三角形的高和宽n
    int n;
    cin >> n;

    // 当前要输出的数字，从1开始
    int num = 1;

    // 外层循环控制行数，一共输出n行
    for (int i = 1; i <= n; i++) {
        // 内层循环控制每行输出的数字个数
        // 第i行要输出i个数字
        for (int j = 1; j <= i; j++) {
            // 输出当前数字
            cout << num;
            // 如果不是最后一个数字，输出空格
            if (j < i) {
                cout << " ";
            }
            // 数字加1，准备输出下一个数字
            num++;
        }
        // 每行结束后换行
        cout << endl;
    }

    return 0;
}

