using namespace std;

int main() {
    // 外层循环控制被乘数（第一个数），从1到9
    for (int i = 1; i <= 9; i++) {
        // 内层循环控制乘数（第二个数），从1到i
        // 这样保证只打印下三角部分，避免重复
        for (int j = 1; j <= i; j++) {
            // 输出乘法算式，格式为：被乘数*乘数=积
            // 每个算式之间用制表符\t分隔，使输出对齐美观
            cout << i << "*" << j << "=" << i * j << "\t";
        }
        // 每完成一行后换行
        cout << endl;
    }
    return 0;
}

