#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;  // 输入正整数n

    // 从1开始遍历到n，检查每个数是否为完全平方数
    for (int i = 1; i <= n; i++) {
        // 判断i是否为完全平方数的方法：
        // 从1开始尝试平方，如果某个数的平方等于i，则i是完全平方数
        // 这里用另一种更高效的方法：开平方后取整，再平方验证
        int sqrt_i = sqrt(i);  // 计算i的平方根（自动向下取整）
        if (sqrt_i * sqrt_i == i) {  // 如果平方根的平方等于i，说明是完全平方数
            cout << i << " ";  // 输出完全平方数，后面加空格
        }
    }
    cout << endl;  // 输出换行

    return 0;
}

