#include <bits/stdc++.h>
using namespace std;

int main() {
    // 百钱百鸡问题：公鸡5元，母鸡3元，鸡雏1元3只
    // 用100元买100只鸡，求所有可能的方案

    // 枚举公鸡数量：最多20只（5*20=100）
    for (int cock = 0; cock <= 20; cock++) {
        // 枚举母鸡数量：最多33只（3*33=99）
        for (int hen = 0; hen <= 33; hen++) {
            // 鸡雏数量 = 100 - 公鸡 - 母鸡
            int chick = 100 - cock - hen;

            // 鸡雏数量必须是非负整数，且能被3整除（因为3只1元）
            if (chick >= 0 && chick % 3 == 0) {
                // 检查总价是否为100元
                // 公鸡5元，母鸡3元，鸡雏1元3只
                if (cock * 5 + hen * 3 + chick / 3 == 100) {
                    // 输出符合条件的方案
                    cout << cock << " " << hen << " " << chick << endl;
                }
            }
        }
    }

    return 0;
}

