#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义变量t存储要赚取的积分总数
    int t;
    cin >> t;

    // sum用于累加每天获得的积分
    int sum = 0;
    // day表示当前是第几天，从第1天开始
    int day = 1;

    // 使用while循环，当累计积分小于目标积分时继续
    while (sum < t) {
        // 第day天可以获得day个积分
        sum = sum + day;
        // 如果累计积分已经达到或超过目标，退出循环
        if (sum >= t) {
            break;
        }
        // 天数加1，继续下一天
        day++;
    }

    // 输出最少需要的天数
    cout << day << endl;

    return 0;
}

