    // 定义变量m和n，分别表示矩形的高和宽
    int m, n;
    cin >> m >> n;

    // 外层循环控制行数（高）
    for (int i = 1; i <= m; i++) {
        // 内层循环控制列数（宽）
        for (int j = 1; j <= n; j++) {
            // 判断当前位置是否在边界上
            // 第一行(i==1)、最后一行(i==m)、第一列(j==1)、最后一列(j==n)
            if (i == 1 || i == m || j == 1 || j == n) {
                cout << "*";  // 边界位置输出星号
            } else {
                cout << " ";  // 内部位置输出空格
            }
        }
        cout << endl;  // 每行结束后换行
    }

    return 0;
}

