#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义变量：h为初始高度，total为总路程，height为当前反弹高度
    double h, total = 0, height;

    // 输入初始高度
    cin >> h;

    // 初始化：第一次下落前的总路程为0，当前高度为h
    total = 0;
    height = h;

    // 循环10次，模拟每次落地和反弹的过程
    for (int i = 1; i <= 10; i++) {
        // 每次落地前，先加上下落的高度
        total += height;

        // 计算反弹高度（原来高度的一半）
        height = height / 2;

        // 如果不是最后一次落地，还需要加上反弹上升的高度
        // 因为第10次落地后不需要再反弹上升
        if (i < 10) {
            total += height;
        }
    }

    // 输出第10次落地时一共经过的米数
    cout << total << endl;

    // 输出第10次弹跳的高度
    cout << height << endl;

    return 0;
}

