int main() {
    // 定义变量
    char ch;      // 用来存储输入的字符
    int n;        // 用来存储层高

    // 输入字符和层高
    cin >> ch;
    cin >> n;

    // 外层循环：控制打印的行数（从第1行到第n行）
    for (int i = 1; i <= n; i++) {
        // 内层循环1：打印空格
        // 第i行需要打印 n-i 个空格，让金字塔居中
        for (int j = 1; j <= n - i; j++) {
            cout << " ";
        }

        // 内层循环2：打印字符
        // 第i行需要打印 2*i-1 个字符
        for (int k = 1; k <= 2 * i - 1; k++) {
            cout << ch;
        }

        // 每行打印完成后换行
        cout << endl;
    }

    return 0;
}

