#include <bits/stdc++.h>
using namespace std;

int main() {
    int k;  // 天数
    cin >> k;

    int total = 0;  // 总金币数
    int day = 1;    // 当前是第几天
    int n = 1;      // 当前阶段每天收到的金币数

    // 当还没有处理完所有天数时继续循环
    while (day <= k) {
        // 当前阶段要持续n天，每天给n枚金币
        // 但要注意不能超过总天数k
        for (int i = 1; i <= n && day <= k; i++) {
            total += n;  // 每天获得n枚金币
            day++;       // 天数加1
        }
        n++;  // 进入下一个阶段，每天金币数加1
    }

    cout << total << endl;
    return 0;
}

