    // 定义变量n表示序列中元素个数
    int n;
    cin >> n;

    // 声明一维数组，用于存储序列中的元素
    // 根据题目要求，n最大不会超过数组大小，这里使用较大的固定大小
    int a[10005];

    // 循环读入n个元素到数组中
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }

    // 读入要查找的特定值x
    int x;
    cin >> x;

    // 初始化答案为-1，表示未找到
    int ans = -1;

    // 遍历数组，查找x第一次出现的位置
    for (int i = 1; i <= n; i++) {
        // 如果当前元素等于x，记录位置并退出循环
        if (a[i] == x) {
            ans = i;  // 记录第一次出现的位置
            break;    // 找到后立即退出循环，保证是第一次出现
        }
    }

    // 输出结果
    cout << ans << endl;

    return 0;
}

