int main() {
    // 定义变量：n为数组元素个数，x为插入位置，y为要插入的整数
    int n, x, y;
    cin >> n >> x >> y;

    // 因为要在第x个位置插入，数组长度会变为n+1
    // 定义数组长度为1005，比最大可能长度稍大，避免越界
    int a[1005];

    // 输入原有的n个正整数
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }

    // 从第n个位置开始，将元素依次向后移动一位
    // 直到移动到第x个位置为止
    for (int i = n; i >= x; i--) {
        a[i + 1] = a[i];  // 将当前位置的元素复制到下一个位置
    }

    // 在第x个位置插入新的整数y
    a[x] = y;

    // 输出插入后的所有元素，共n+1个
    for (int i = 1; i <= n + 1; i++) {
        cout << a[i];
        // 如果不是最后一个元素，输出空格分隔
        if (i < n + 1) {
            cout << " ";
        }
    }
    cout << endl;  // 输出换行

    return 0;
}

