#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义变量n和k，n表示工位数量，k表示右移位数
    int n, k;
    cin >> n >> k;

    // 定义数组a，用于存储n个工位的状态
    int a[1005];  // 题目说n<=1000，多开一点空间

    // 输入n个工位的初始状态
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }

    // 处理k可能大于n的情况，取模运算得到实际需要移动的位数
    // 因为移动n次相当于回到原位，所以只需要移动k%n次
    k = k % n;

    // 如果k为0，说明不需要移动，直接输出原数组
    if (k == 0) {
        for (int i = 0; i < n; i++) {
            cout << a[i] << " ";
        }
        cout << endl;
        return 0;
    }

    // 创建一个临时数组b，用于存储移动后的结果
    int b[1005];

    // 将原数组的后k个元素（即最后k个工位）放到新数组的前面
    // 原数组下标从n-k到n-1的元素，对应新数组下标从0到k-1
    for (int i = 0; i < k; i++) {
        b[i] = a[n - k + i];
    }

    // 将原数组的前n-k个元素（即前面n-k个工位）放到新数组的后面
    // 原数组下标从0到n-k-1的元素，对应新数组下标从k到n-1
    for (int i = 0; i < n - k; i++) {
        b[k + i] = a[i];
    }

    // 输出移动后的工位状态序列
    for (int i = 0; i < n; i++) {
        cout << b[i] << " ";
    }
    cout << endl;

    return 0;
}

