    }

    // 标记是否有安全的洞穴
    bool hasSafe = false;

    // 从1到n遍历所有洞穴
    for (int i = 1; i <= n; i++) {
        // 如果visited[i]为0，说明该洞穴没有被造访过，是安全的
        if (visited[i] == 0) {
            cout << i << " ";  // 输出安全的洞穴编号
            hasSafe = true;    // 标记存在安全洞穴
        }
    }

    // 如果没有安全的洞穴，输出"555~"
    if (hasSafe == false) {
        cout << "555~";
    }

    cout << endl;  // 输出换行
    return 0;
}

