    // 声明一维数组存储海拔高度
    int height[1005];  // 假设n不超过1000

    // 输入n个海拔高度
    for (int i = 0; i < n; i++) {
        cin >> height[i];
    }

    // 初始化最长平台长度为1（至少有一个数）
    int maxLen = 1;
    // 当前连续相同海拔的长度，从第一个数开始计数
    int currentLen = 1;

    // 从第二个数开始遍历数组
    for (int i = 1; i < n; i++) {
        // 如果当前海拔和前一个相同，则当前平台长度+1
        if (height[i] == height[i-1]) {
            currentLen++;
        } else {
            // 如果不同，说明当前平台结束，更新最长平台长度
            if (currentLen > maxLen) {
                maxLen = currentLen;
            }
            // 重置当前平台长度为1（当前数作为新平台的开始）
            currentLen = 1;
        }
    }

    // 循环结束后，还需要比较最后一次的平台长度
    if (currentLen > maxLen) {
        maxLen = currentLen;
    }

    // 输出最长平台长度
    cout << maxLen << endl;

    return 0;
}

