#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义变量n，表示序列长度
    int n;
    cin >> n;

    // 定义数组a，用于存储输入的n个数字
    // 题目说明n<=20000，数字最大不超过20000
    int a[20005];

    // 循环读入n个数字到数组中
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }

    // 使用冒泡排序对数组进行从小到大排序
    // 外层循环控制排序轮数，共需要n-1轮
    for (int i = 0; i < n - 1; i++) {
        // 内层循环进行相邻元素的比较和交换
        // 每轮结束后，最大的数会"冒泡"到最后面
        for (int j = 0; j < n - 1 - i; j++) {
            // 如果前面的数大于后面的数，则交换它们
            if (a[j] > a[j + 1]) {
                // 使用临时变量temp完成交换
                int temp = a[j];
                a[j] = a[j + 1];
                a[j + 1] = temp;
            }
        }
    }

    // 输出排序后的结果
    // 第一个数字前不输出空格
    cout << a[0];
    // 从第二个数字开始，每个数字前输出一个空格
    for (int i = 1; i < n; i++) {
        cout << " " << a[i];
    }
    cout << endl;

    return 0;
}

