    // 定义计数器，用于统计小写字母的个数
    int cnt = 0;

    // 遍历字符串中的每一个字符
    // 使用 .length() 获取字符串长度
    for (int i = 0; i < s.length(); i++) {
        // 判断当前字符是否为小写字母
        // 小写字母的ASCII码范围是97~122（即'a'~'z'）
        if (s[i] >= 'a' && s[i] <= 'z') {
            cnt++;  // 如果是小写字母，计数器加1
        }
    }

    // 输出小写字母的个数
    cout << cnt << endl;

    return 0;
}

