#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义字符串变量，用于存储输入的整行内容
    string s;
    // 使用 getline 读取包含空格的整行字符串
    getline(cin, s);

    // 定义结果字符串，用于存储过滤空格后的字符
    string result = "";

    // 遍历原字符串中的每一个字符
    for (int i = 0; i < s.length(); i++) {
        // 如果当前字符不是空格，则将其添加到结果字符串中
        if (s[i] != ' ') {
            result += s[i];
        }
        // 如果是空格，则跳过（不添加到结果中）
    }

    // 输出过滤空格后的结果字符串
    cout << result << endl;

    return 0;
}

