int main() {
    // 定义两个字符串，分别存储两条光线
    string s1, s2;

    // 读取两行输入（包含空格，所以用getline）
    getline(cin, s1);
    getline(cin, s2);

    // 将s1中的小写字母转换为大写
    for (int i = 0; i < s1.length(); i++) {
        // 判断字符是否为小写字母（ASCII码97-122）
        if (s1[i] >= 'a' && s1[i] <= 'z') {
            // 小写转大写：ASCII码减32
            s1[i] = s1[i] - 32;
        }
    }

    // 将s2中的小写字母转换为大写
    for (int i = 0; i < s2.length(); i++) {
        if (s2[i] >= 'a' && s2[i] <= 'z') {
            s2[i] = s2[i] - 32;
        }
    }

    // 比较两个字符串的字典序
    // 如果s1的字典序大于等于s2，则s1在前，s2在后
    // 否则s2在前，s1在后
    if (s1 >= s2) {
        cout << s1 << s2 << endl;
    } else {
        cout << s2 << s1 << endl;
    }

    return 0;
}

