#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义字符串变量，用于存储输入的字符串
    string s;
    // 读取输入的字符串
    cin >> s;

    // 获取字符串的长度
    int len = s.length();

    // 判断第一个字符是否合法（不能是数字）
    // 如果第一个字符是数字，直接输出no并结束程序
    if (isdigit(s[0])) {
        cout << "no" << endl;
        return 0;
    }

    // 遍历字符串中的每一个字符
    for (int i = 0; i < len; i++) {
        // 判断当前字符是否合法
        // 合法字符包括：字母（大小写）、数字、下划线
        // 注意：数字不能作为第一个字符，但可以在其他位置出现
        if (!(isalpha(s[i]) || isdigit(s[i]) || s[i] == '_')) {
            // 如果遇到不合法字符，输出no并结束程序
            cout << "no" << endl;
            return 0;
        }
    }

    // 所有字符都检查通过，说明是合法标识符
    cout << "yes" << endl;

    return 0;
}

