using namespace std;

int main() {
    // 定义变量存储范围 l 和 r
    int l, r;
    // 输入范围
    cin >> l >> r;

    // 注意：输入范围后，换行符还在输入缓冲区中
    // 需要使用 getline 读取字符串，但需要先处理掉换行符
    string s;
    // 使用 getline 读取整行字符串（包括空格）
    getline(cin, s);  // 这里会读取到第一行末尾的换行符
    getline(cin, s);  // 这里才是真正的第二行字符串

    // 遍历指定范围 l~r 内的字符并输出
    // 注意：字符串下标从0开始，所以实际要输出的是 s[l-1] 到 s[r-1]
    for (int i = l - 1; i < r; i++) {
        cout << s[i];
    }
    cout << endl;

