#include <bits/stdc++.h>
using namespace std;

int main() {
    // 读取整行字符串，包含空格
    string s;
    getline(cin, s);

    int n = s.length();  // 字符串长度
    int count = 0;       // 当前单词的长度计数器
    bool first = true;   // 标记是否是第一个单词，用于控制逗号输出

    // 遍历字符串中的每个字符
    for (int i = 0; i < n; i++) {
        if (s[i] != ' ') {
            // 如果不是空格，说明还在同一个单词中，长度加1
            count++;
        } else {
            // 遇到空格，说明一个单词结束
            if (count > 0) {
                // 如果当前单词长度大于0，说明确实有单词结束
                if (!first) {
                    // 不是第一个单词，先输出逗号
                    cout << ",";
                }
                // 输出当前单词的长度
                cout << count;
                first = false;  // 标记已经有单词输出了
                count = 0;      // 重置计数器，准备统计下一个单词
            }
            // 如果count为0，说明是连续的空格，直接跳过
        }
    }

    // 处理最后一个单词（如果字符串末尾没有空格）
    if (count > 0) {
        if (!first) {
            cout << ",";
        }
        cout << count;
    }

    cout << endl;
    return 0;
}

