#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义字符串变量存储原始信息
    string s;
    // 定义整数变量存储平移位数
    int n;

    // 输入原始字符串
    cin >> s;
    // 输入平移位数
    cin >> n;

    // 遍历字符串中的每个字符
    for (int i = 0; i < s.length(); i++) {
        // 判断当前字符是否为大写字母
        if (s[i] >= 'A' && s[i] <= 'Z') {
            // 大写字母向后平移n位
            // 先计算当前字母在字母表中的位置(0-25)，加上n后对26取模
            // 再加上'A'的ASCII码得到加密后的字符
            s[i] = (s[i] - 'A' + n) % 26 + 'A';
        }
        // 判断当前字符是否为小写字母
        else if (s[i] >= 'a' && s[i] <= 'z') {
            // 小写字母向后平移n位
            // 先计算当前字母在字母表中的位置(0-25)，加上n后对26取模
            // 再加上'a'的ASCII码得到加密后的字符
            s[i] = (s[i] - 'a' + n) % 26 + 'a';
        }
        // 题目保证只包含英文字母，所以不需要处理其他字符
    }

    // 输出加密后的字符串
    cout << s << endl;

    return 0;
}

