#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义两个字符串变量
    string mainStr;   // 主串（原始字符串）
    string subStr;    // 子串（目标字符串）

    // 读入两行字符串
    cin >> mainStr;
    cin >> subStr;

    // 获取两个字符串的长度
    int mainLen = mainStr.length();   // 主串长度
    int subLen = subStr.length();     // 子串长度

    // 标记是否找到子串
    bool found = false;

    // 在主串中逐个位置尝试匹配子串
    // 只需要遍历到 mainLen - subLen 位置即可
    // 因为如果起始位置超过这个范围，剩余字符不够子串长度
    for (int i = 0; i <= mainLen - subLen; i++) {
        // 检查从位置i开始的子串是否匹配
        bool match = true;

        // 逐个字符比较
        for (int j = 0; j < subLen; j++) {
            // 如果有一个字符不相等，匹配失败
            if (mainStr[i + j] != subStr[j]) {
                match = false;
                break;
            }
        }

        // 如果匹配成功，标记找到并退出循环
        if (match) {
            found = true;
            break;
        }
    }

    // 根据查找结果输出
    if (found) {
        cout << "找到了" << endl;
    } else {
        cout << "没找到" << endl;
    }

    return 0;
}

