    // 定义两个字符串
    string s1, s2;
    // 输入原始字符串和目标子串
    cin >> s1 >> s2;

    // 获取两个字符串的长度
    int len1 = s1.length();
    int len2 = s2.length();

    // 如果目标子串比原始字符串长，则不可能成为子串
    // 因为循环移位不会改变字符串长度
    if (len2 > len1) {
        cout << "false" << endl;
        return 0;
    }

    // 将s1复制一份拼接到自己后面，形成长度为2*len1的新字符串
    // 这样，s1的所有循环移位结果都会出现在这个新字符串中
    // 例如：s1="ABCD"，拼接后为"ABCDABCD"
    // 循环移位得到"BCDA"、"CDAB"、"DABC"都是"ABCDABCD"的子串
    string double_s1 = s1 + s1;

    // 在double_s1中查找s2
    // string的find函数会返回s2第一次出现的位置
    // 如果找不到，返回string::npos（一个很大的数）
    size_t pos = double_s1.find(s2);

    // 判断是否找到
    if (pos != string::npos) {
        // 找到了，但需要确保找到的位置在原始字符串长度范围内
        // 因为s2的长度不能超过len1，所以如果找到的位置在0到len1-1之间
        // 就说明s2是某个循环移位结果的子串
        if (pos < len1) {
            cout << "true" << endl;
        } else {
            cout << "false" << endl;
        }
    } else {
        cout << "false" << endl;
    }

    return 0;
}

