#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义字符串变量，用于存储输入的原始字符串
    string s;
    // 从标准输入读取一行字符串
    cin >> s;

    // 获取字符串的长度
    int len = s.length();

    // 遍历字符串中的每一个字符
    for (int i = 0; i < len; i++) {
        // 判断当前字符是否为'z'
        if (s[i] == 'z') {
            // 如果是'z'，则向后移动1位变成'a'（循环移位）
            s[i] = 'a';
        } else {
            // 如果不是'z'，则直接将字符的ASCII码加1
            // 例如：'a'变成'b'，'b'变成'c'，以此类推
            s[i] = s[i] + 1;
        }
    }

    // 输出加密后的字符串
    cout << s << endl;

    return 0;
}

