#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义字符串变量存储原始输入
    string s;
    int n;

    // 读取一整行字符串（包含空格）
    getline(cin, s);
    // 读取平移位数
    cin >> n;

    // 如果n为负数，取其绝对值
    if (n < 0) {
        n = -n;
    }

    // 遍历字符串中的每个字符
    for (int i = 0; i < s.length(); i++) {
        char c = s[i];

        // 判断是否为大写字母
        if (c >= 'A' && c <= 'Z') {
            // 将大写字母向后平移n位，并在A~Z范围内循环
            // 计算过程：先减去'A'得到0~25的数字，加上n，再对26取模，最后加回'A'
            s[i] = (c - 'A' + n) % 26 + 'A';
        }
        // 判断是否为小写字母
        else if (c >= 'a' && c <= 'z') {
            // 将小写字母向后平移n位，并在a~z范围内循环
            s[i] = (c - 'a' + n) % 26 + 'a';
        }
        // 非字母字符保持不变（不需要处理）
    }

    // 输出加密后的字符串
    cout << s << endl;

    return 0;
}

