int main() {
    // 读入一行字符串，可能包含空格
    string text;
    getline(cin, text);

    // 查找第一个 <tag> 的位置
    int startPos = text.find("<tag>");

    // 如果没有找到 <tag>，则输出 false
    if (startPos == string::npos) {
        cout << "false" << endl;
        return 0;
    }

    // 查找第一个 </tag> 的位置，从 <tag> 后面开始找
    int endPos = text.find("</tag>", startPos + 5);  // 5是"<tag>"的长度

    // 如果没有找到 </tag>，则输出 false
    if (endPos == string::npos) {
        cout << "false" << endl;
        return 0;
    }

    // 提取 <tag> 和 </tag> 之间的内容
    // startPos + 5 是 <tag> 结束后的第一个字符位置
    // endPos 是 </tag> 开始的位置
    string content = text.substr(startPos + 5, endPos - startPos - 5);

    // 输出结果
    cout << content << endl;

    return 0;
}

