#include <bits/stdc++.h>
using namespace std;

// 判断一个数是否为质数的函数
// 参数：x - 要判断的整数
// 返回值：true 表示是质数，false 表示不是质数
bool isprime(int x) {
    // 1不是质数，小于等于1的数都不是质数
    if (x <= 1) {
        return false;
    }
    // 2是质数
    if (x == 2) {
        return true;
    }
    // 偶数除了2都不是质数
    if (x % 2 == 0) {
        return false;
    }
    // 从3开始检查奇数因子，只需要检查到sqrt(x)
    for (int i = 3; i * i <= x; i += 2) {
        if (x % i == 0) {
            return false;
        }
    }
    return true;
}

int main() {
    int n;
    cin >> n;

    // 遍历所有不大于n的正整数对(i, i+1)
    // 因为题目要求"相邻两数"，所以只需要检查相邻的两个数
    for (int i = 1; i < n; i++) {
        // 计算相邻两数之和
        int sum = i + (i + 1);
        // 如果和为质数，则输出这对数
        if (isprime(sum)) {
            cout << i << " " << i + 1 << endl;
        }
    }

    return 0;
}

