// 判断一个数是否为素数
bool isPrime(int n) {
    if (n < 2) return false;  // 小于2的数不是素数
    for (int i = 2; i * i <= n; i++) {  // 只需要检查到平方根
        if (n % i == 0) return false;   // 如果能被整除，不是素数
    }
    return true;  // 是素数
}

// 判断一个数是否为回文数
bool isPalindrome(int n) {
    int original = n;  // 保存原始数值
    int reversed = 0;  // 用于存储反转后的数字

    // 将数字反转
    while (n > 0) {
        reversed = reversed * 10 + n % 10;  // 取出最后一位，加到反转数后面
        n = n / 10;  // 去掉最后一位
    }

    return original == reversed;  // 如果反转后相等，就是回文数
}

int main() {
    bool first = true;  // 标记是否是第一个输出的数，用于控制空格

    // 遍历1到1000的所有数
    for (int i = 1; i <= 1000; i++) {
        // 同时满足素数和回文数两个条件
        if (isPrime(i) && isPalindrome(i)) {
            if (first) {
                cout << i;      // 第一个数前面不加空格
                first = false;
            } else {
                cout << " " << i;  // 后面的数前面加空格
            }
        }
    }
    cout << endl;  // 输出换行

    return 0;
}

