#include <bits/stdc++.h>
using namespace std;

// 函数功能：计算字符串中所有字母的乘积对47的余数
// 参数：s - 输入的大写字母字符串
// 返回值：乘积对47的余数
int computeMod(string s) {
    int product = 1;  // 乘积初始化为1
    // 遍历字符串中的每个字符
    for (int i = 0; i < s.length(); i++) {
        // 将字母转换为数字：A=1, B=2, ..., Z=26
        int num = s[i] - 'A' + 1;
        product = product * num;  // 累乘
    }
    return product % 47;  // 返回乘积对47的余数
}

int main() {
    string person, planet;  // 人的信息和星球信息

    // 读取两行输入
    getline(cin, person);
    getline(cin, planet);

    // 计算人和星球信息的余数
    int personMod = computeMod(person);
    int planetMod = computeMod(planet);

    // 判断是否同频并输出结果
    if (personMod == planetMod) {
        cout << "yes" << endl;
    } else {
        cout << "no" << endl;
    }

    return 0;
}

