#include <bits/stdc++.h>
using namespace std;

// 函数：对单个字符进行凯撒加密
// 参数：ch 需要加密的字符，n 平移的位数
// 返回值：加密后的字符
char encryptChar(char ch, int n) {
    // 判断字符是大写还是小写
    if (ch >= 'A' && ch <= 'Z') {
        // 大写字母：先减去'A'得到0-25的数字，加上n后对26取模，再加回'A'
        return (ch - 'A' + n) % 26 + 'A';
    } else if (ch >= 'a' && ch <= 'z') {
        // 小写字母：先减去'a'得到0-25的数字，加上n后对26取模，再加回'a'
        return (ch - 'a' + n) % 26 + 'a';
    }
    // 如果不是字母（题目保证只有大小写字母，但保留原样作为安全处理）
    return ch;
}

// 函数：对整个字符串进行凯撒加密
// 参数：s 需要加密的字符串，n 平移的位数
// 返回值：加密后的字符串
string encryptString(string s, int n) {
    string result = "";  // 存储加密结果
    // 遍历字符串中的每个字符
    for (int i = 0; i < s.length(); i++) {
        // 调用encryptChar函数加密当前字符，并添加到结果中
        result += encryptChar(s[i], n);
    }
    return result;
}

int main() {
    string s;      // 存储输入的字符串
    int n;         // 存储平移的位数

    // 读取输入：第一行是字符串，第二行是整数
    cin >> s;
    cin >> n;

    // 调用encryptString函数进行加密，并输出结果
    cout << encryptString(s, n) << endl;

    return 0;
}

