#include <bits/stdc++.h>
using namespace std;

// 函数：在字符串s的pos位置插入字符串str
// 参数：s - 原字符串（传值，不会修改原字符串）
//       pos - 插入位置（从0开始）
//       str - 待插入的字符串
// 返回值：插入后的新字符串
string insertString(string s, int pos, string str) {
    string result = "";  // 存储插入后的结果

    // 情况1：如果pos超出原字符串长度，直接在末尾追加
    if (pos >= (int)s.length()) {
        result = s + str;
        return result;
    }

    // 情况2：正常插入
    // 先取s的前pos个字符
    for (int i = 0; i < pos; i++) {
        result = result + s[i];
    }
    // 插入str
    result = result + str;
    // 再取s从pos开始的剩余字符
    for (int i = pos; i < (int)s.length(); i++) {
        result = result + s[i];
    }

    return result;
}

int main() {
    string s;      // 原始字符串
    int t;         // 操作次数

    // 读入原始字符串和操作次数
    cin >> s >> t;

    // 循环执行t次插入操作
    for (int i = 0; i < t; i++) {
        int pos;          // 插入位置
        string str;       // 待插入的字符串

        // 读入插入位置和待插入字符串
        cin >> pos >> str;

        // 调用函数进行插入，更新字符串s
        s = insertString(s, pos, str);
    }

    // 输出最终结果
