// 加密函数：将字符串s中的每个字母右移n位
string lock(string s, int n) {
    string result = "";  // 存储加密后的结果
    for (int i = 0; i < s.length(); i++) {
        char c = s[i];
        if (c >= 'A' && c <= 'Z') {  // 大写字母处理
            // 右移n位，注意取模26保证循环
            c = 'A' + (c - 'A' + n) % 26;
        } else if (c >= 'a' && c <= 'z') {  // 小写字母处理
            c = 'a' + (c - 'a' + n) % 26;
        }
        result = result + c;  // 将处理后的字符添加到结果中
    }
    return result;
}

// 解密函数：将字符串s中的每个字母左移n位
string unlock(string s, int n) {
    string result = "";  // 存储解密后的结果
    for (int i = 0; i < s.length(); i++) {
        char c = s[i];
        if (c >= 'A' && c <= 'Z') {  // 大写字母处理
            // 左移n位相当于右移(26-n)位，注意取模26保证循环
            c = 'A' + (c - 'A' + 26 - n) % 26;
        } else if (c >= 'a' && c <= 'z') {  // 小写字母处理
            c = 'a' + (c - 'a' + 26 - n) % 26;
        }
        result = result + c;  // 将处理后的字符添加到结果中
    }
    return result;
}

