    // 小于2的数不是质数
    if (n < 2) {
        return false;
    }
    // 从2到n-1检查是否有因子
    for (int i = 2; i < n; i++) {
        if (n % i == 0) {
            return false;  // 有因子，不是质数
        }
    }
    return true;  // 没有因子，是质数
}

