    // 下标0对应'a'，下标1对应'b'，以此类推
    int count[26] = {0};

    // 遍历单词中的每个字符，统计出现次数
    for (int i = 0; i < word.length(); i++) {
        int index = word[i] - 'a';  // 将字母转换为0-25的数字
        count[index]++;
    }

    // 找出出现次数的最大值和最小值
    int maxn = 0;  // 最大出现次数
    int minn = 100;  // 最小出现次数，初始化为一个较大的数

