#include <bits/stdc++.h>
using namespace std;

// 函数功能：计算一个数的所有因数（不包括自身）之和
// 参数：n - 要计算的自然数
// 返回值：因数之和
int sumOfFactors(int n) {
    int sum = 0;
    // 从1遍历到n/2，找出所有能整除n的数
    for (int i = 1; i <= n / 2; i++) {
        if (n % i == 0) {
            sum += i;  // 累加因数
        }
    }
    return sum;
}

int main() {
    // 遍历3000以内的所有自然数
    for (int a = 1; a <= 3000; a++) {
        int b = sumOfFactors(a);  // 计算a的因数之和，得到b

        // 条件1：a != b（排除自身等于自身的情况）
        // 条件2：b <= 3000（确保b也在3000以内）
        // 条件3：a < b（避免重复输出，只输出a<b的情况）
        // 条件4：sumOfFactors(b) == a（验证b的因数之和是否等于a）
        if (a != b && b <= 3000 && a < b && sumOfFactors(b) == a) {
            cout << a << " " << b << endl;  // 输出亲和数对
        }
    }

    return 0;
}

