// 函数功能：计算一个数的各位数字之和
// 参数：num - 要计算的整数
// 返回值：各位数字之和
int sumDigits(int num) {
    int sum = 0;
    // 循环取出每一位数字并累加
    while (num > 0) {
        sum += num % 10;  // 取出个位数字
        num /= 10;        // 去掉个位数字
    }
    return sum;
}

// 函数功能：计算一个数的数根
// 参数：n - 输入的正整数
// 返回值：数根（一位数）
int digitalRoot(int n) {
    // 当n不是一位数时，继续计算各位数字之和
    while (n >= 10) {
        n = sumDigits(n);  // 计算各位数字之和，更新n的值
    }
    return n;  // 返回最终得到的一位数
}

