bool isPrime(int num) {
    if (num < 2) return false;  // 1不是素数
    for (int i = 2; i * i <= num; i++) {
        if (num % i == 0) return false;  // 能被整除则不是素数
    }
    return true;
}

// 判断字符串表示的数字是否为回文数
bool isPalindrome(string s) {
    int len = s.length();
    for (int i = 0; i < len / 2; i++) {
        if (s[i] != s[len - 1 - i]) return false;  // 对称位置字符不同
    }
    return true;
}

// 计算字符串表示的数字的各位数字之和
int digitSum(string s) {
    int sum = 0;
    for (int i = 0; i < s.length(); i++) {
        sum += s[i] - '0';  // 字符转数字
    }
    return sum;
}

int main() {
    string n;
    cin >> n;  // 输入大整数（用字符串存储）

    // 第一步：判断是否为回文数
    if (!isPalindrome(n)) {
        cout << "no" << endl;
        return 0;
    }

    // 第二步：计算各位数字之和
    int sum = digitSum(n);

    // 第三步：判断各位数字之和是否为素数
    if (isPrime(sum)) {
        cout << "yes" << endl;
    } else {
        cout << "no" << endl;
    }

    return 0;
}

