#include <bits/stdc++.h>
using namespace std;

// 函数功能：判断字符串s是否为回文数
// 参数：s - 输入的字符串形式的正整数
// 返回值：如果是回文数返回true，否则返回false
bool isPalindrome(string s) {
    int left = 0;          // 左指针，指向字符串开头
    int right = s.size() - 1;  // 右指针，指向字符串末尾

    // 当左指针小于右指针时，继续比较
    while (left < right) {
        // 如果左右指针指向的字符不同，说明不是回文数
        if (s[left] != s[right]) {
            return false;
        }
        // 左指针右移，右指针左移，继续比较下一对字符
        left++;
        right--;
    }
    // 所有字符都匹配，是回文数
    return true;
}

int main() {
    string num;  // 存储输入的超大正整数（用字符串存储）
    cin >> num;  // 输入字符串形式的正整数

    // 调用函数判断是否为回文数
    if (isPalindrome(num)) {
        cout << "yes" << endl;  // 是回文数
    } else {
        cout << "no" << endl;   // 不是回文数
    }

    return 0;
}

