// 函数功能：计算n的阶乘
// 参数：n - 要计算阶乘的数
// 返回值：n的阶乘结果
long long factorial(int n) {
    long long result = 1;  // 用long long防止溢出
    for (int i = 1; i <= n; i++) {
        result *= i;  // 累乘计算阶乘
    }
    return result;
}

int main() {
    int n, m;
    cin >> n >> m;  // 输入n和m

    // 根据公式计算：n! / ((n-m)! * m!)
    // 先分别计算三个阶乘
    long long n_fact = factorial(n);           // 计算n!
    long long nm_fact = factorial(n - m);      // 计算(n-m)!
    long long m_fact = factorial(m);           // 计算m!

    // 计算最终结果
    long long result = n_fact / (nm_fact * m_fact);

    cout << result << endl;  // 输出结果

    return 0;
}

