    int N;
    cin >> N;  // 读入数字个数

    // 循环处理每个字符串
    for (int i = 0; i < N; i++) {
        string s;
        cin >> s;  // 读入一个数字字符串

        // 初始化四个标志位，1表示可能，0表示不可能
        int bin = 1;   // 二进制
        int oct = 1;   // 八进制
        int dec = 1;   // 十进制
        int hex = 1;   // 十六进制

        // 遍历字符串中的每个字符
        for (int j = 0; j < s.length(); j++) {
            char c = s[j];

            // 判断当前字符是否超出各进制的数字范围
            // 二进制只能包含0和1
            if (c >= '2') {
                bin = 0;  // 出现2及以上的数字，不可能是二进制
            }
            // 八进制只能包含0-7
            if (c >= '8') {
                oct = 0;  // 出现8及以上的数字，不可能是八进制
            }
            // 十进制只能包含0-9
            if (c >= 'A') {
                dec = 0;  // 出现字母，不可能是十进制
            }
            // 十六进制可以包含0-9和A-F
            if (c > 'F') {
                hex = 0;  // 出现大于F的字母，不可能是十六进制
            }
        }

        // 输出结果，每个数之间用空格隔开
        cout << bin << " " << oct << " " << dec << " " << hex << endl;
    }

    return 0;
}

