#include <bits/stdc++.h>
using namespace std;

int main() {
    // 读入二进制字符串
    string s;
    cin >> s;

    // 记录转换后的十进制结果
    int decimal = 0;

    // 从最高位（字符串最左边）开始处理
    // 对于二进制数，每一位的权值是2的幂次
    // 例如：1011 = 1*2^3 + 0*2^2 + 1*2^1 + 1*2^0
    for (int i = 0; i < s.length(); i++) {
        // 将当前结果左移一位（相当于乘以2），为下一位腾出位置
        decimal = decimal << 1;

        // 如果当前位是'1'，则加上1（因为左移后最低位是0）
        // 如果当前位是'0'，则不需要加任何数
        if (s[i] == '1') {
            decimal = decimal | 1;  // 将最低位设为1
        }
    }

    // 输出十进制结果
    cout << decimal << endl;

    return 0;
}

