#include <bits/stdc++.h>
using namespace std;

int main() {
    // 输入位置x
    int x;
    cin >> x;

    // 位权 = 进制^(x-1)
    // 因为从右往左数第1位是进制^0，第2位是进制^1，以此类推
    // 第x位就是进制^(x-1)

    // 计算二进制下的位权：2^(x-1)
    int binary = 1 << (x - 1);  // 用左移运算符计算2的幂

    // 计算四进制下的位权：4^(x-1)
    int quaternary = 1;
    for (int i = 1; i < x; i++) {
        quaternary *= 4;
    }

    // 计算八进制下的位权：8^(x-1)
    int octal = 1;
    for (int i = 1; i < x; i++) {
        octal *= 8;
    }

    // 计算十六进制下的位权：16^(x-1)
    int hexadecimal = 1;
    for (int i = 1; i < x; i++) {
        hexadecimal *= 16;
    }

    // 输出四个位权，用空格隔开
    cout << binary << " " << quaternary << " " << octal << " " << hexadecimal << endl;

    return 0;
}

