    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }

    // 读取密钥
    int key;
    cin >> key;

    // 对每个整数进行加密：先按位非(~)，再与密钥按位与(&)
    for (int i = 0; i < n; i++) {
        // 第一步：对原始整数进行按位非操作
        int temp = ~nums[i];
        // 第二步：将结果与密钥进行按位与操作
        int encrypted = temp & key;

        // 输出加密后的结果，每个数后面跟一个空格
        cout << encrypted;
        if (i < n - 1) {
            cout << " ";
        }
    }
    cout << endl;

    return 0;
}

