#include <bits/stdc++.h>
using namespace std;

int main() {
    // 读入三进制字符串
    string s;
    cin >> s;

    // 1. 将三进制字符串转换为十进制整数
    int decimal = 0;
    for (int i = 0; i < s.length(); i++) {
        // 当前位的数字（字符转数字）
        int digit = s[i] - '0';
        // 三进制转十进制：每次乘以3再加上当前位
        decimal = decimal * 3 + digit;
    }

    // 2. 将十进制整数转换为八进制
    // 因为字符串长度不超过8，三进制最大为22222222，转换为十进制不超过6560
    // 八进制最多5位，用数组存储每一位
    int octal[10];  // 存储八进制每一位
    int len = 0;    // 八进制位数

    // 特殊情况：如果十进制为0，直接输出0
    if (decimal == 0) {
        cout << 0 << endl;
        return 0;
    }

    // 除8取余法：不断除以8，余数就是八进制的一位
    while (decimal > 0) {
        octal[len] = decimal % 8;  // 取余数
        decimal = decimal / 8;     // 整除8
        len++;
    }

    // 3. 逆序输出八进制数（最后得到的余数是最高位）
    for (int i = len - 1; i >= 0; i--) {
        cout << octal[i];
    }
    cout << endl;

    return 0;
}

