#include <bits/stdc++.h>
using namespace std;

int main() {
    int x;
    cin >> x;

    // 计算 ~x，注意int是32位，~x会得到所有位取反的结果
    int not_x = ~x;

    // 计算 (x ^ ~x)，根据异或性质，相同为0，不同为1
    // 因为x和~x每一位都相反，所以结果每一位都是1
    // 即 (x ^ ~x) = -1 (所有位都是1)
    int xor_result = x ^ not_x;  // 这个值恒等于-1

    // 所以原方程变为：-1 + (x & y) + (x | y) = 2025
    // 即 (x & y) + (x | y) = 2026

    // 关键性质：对于任意两个数a和b，有 a + b = (a & b) + (a | b)
    // 证明：a + b = (a ^ b) + 2*(a & b) = (a & b) + (a | b)
    // 因为 a | b = (a ^ b) + (a & b)
    // 所以 (x & y) + (x | y) = x + y

    // 因此方程简化为：x + y = 2026
    // 即 y = 2026 - x

    int y = 2026 - x;

    // 检查y是否为正整数
    if (y > 0) {
        cout << y << endl;
    } else {
        cout << -1 << endl;
    }

    return 0;
}

