    // 定义矩阵的行数和列数
    int n, m;
    cin >> n >> m;

    // 声明二维数组，用于存储矩阵
    // 注意：题目没有给出矩阵元素的范围，我们使用较大的固定大小
    // 实际教学中可以根据需要动态调整，但这里为了简单，使用固定大小
    int a[105][105];  // 假设 n, m <= 100

    // 输入矩阵的每个元素
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cin >> a[i][j];
        }
    }

    // 初始化最大值及其下标
    // 先假设第一个元素是最大值
    int maxValue = a[0][0];
    int maxRow = 0;
    int maxCol = 0;

    // 遍历整个矩阵，寻找最大值及其下标
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            // 如果当前元素比记录的最大值还大，就更新最大值及其下标
            if (a[i][j] > maxValue) {
                maxValue = a[i][j];
                maxRow = i;
                maxCol = j;
            }
        }
    }

    // 输出最大值的行下标和列下标，用空格隔开
    cout << maxRow << " " << maxCol << endl;

    return 0;
}

