int main() {
    // 定义变量：n行，m列，差值阈值k
    int n, m, k;
    cin >> n >> m >> k;

    // 定义两个二维数组，分别存储两张图片的像素值
    // 注意：题目中n和m最大可能为1000，但为了安全，可以开大一点
    int a[1005][1005], b[1005][1005];

    // 读入第一张图片的像素值
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            cin >> a[i][j];
        }
    }

    // 读入第二张图片的像素值
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            cin >> b[i][j];
        }
    }

    // 计数器，记录符合条件的位置数量
    int count = 0;

    // 遍历每个位置，检查像素值差的绝对值是否小于等于k
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            // 计算两个像素值的差，取绝对值
            int diff = a[i][j] - b[i][j];
            if (diff < 0) {
                diff = -diff;  // 取绝对值
            }
            // 如果差值小于等于k，则计数加1
            if (diff <= k) {
                count++;
            }
        }
    }

    // 输出结果
    cout << count << endl;

    return 0;
}

