int main() {
	int n, m;
	int x1, y1, x2, y2;
	int p1, q1, p2, q2;

	cin >> n >> m;

	// 使用双重循环输入方阵中每个精灵的战斗力
	// 注意：数组下标从1开始使用，符合题目中坐标从1开始的要求
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			cin >> a[i][j];
		}
	}

	// 读取第一个子方阵的坐标
	cin >> x1 >> y1 >> x2 >> y2;
	// 读取第二个子方阵的坐标
	cin >> p1 >> q1 >> p2 >> q2;

	int sum1 = 0;
	// 计算第一个子方阵的战斗力总和
	for (int i = x1; i <= x2; i++) {        // 遍历第一个子方阵的行范围
		for (int j = y1; j <= y2; j++) {    // 遍历第一个子方阵的列范围
			sum1 += a[i][j];
		}
	}

	int sum2 = 0;
	// 计算第二个子方阵的战斗力总和
	for (int i = p1; i <= p2; i++) {        // 遍历第二个子方阵的行范围
		for (int j = q1; j <= q2; j++) {    // 遍历第二个子方阵的列范围
			sum2 += a[i][j];
		}
	}

	// 比较两个子方阵的战斗力总和，输出相应结果
	if (sum1 > sum2) {
		cout << "Victory";  // 第一支小队更强
	} else if (sum1 < sum2) {
		cout << "Defeat";   // 第二支小队更强
	} else {
		cout << "Draw";     // 两队战斗力相等
	}

	return 0;
}

