    int a[105][105];

    // 输入矩阵数据
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            cin >> a[i][j];
        }
    }

    // 定义两个数组：
    // rowMin[i] 存储第i行的最小值
    // colMax[j] 存储第j列的最大值
    int rowMin[105], colMax[105];

    // 初始化：行最小值设为很大的数，列最大值设为很小的数
    for (int i = 1; i <= n; i++) {
        rowMin[i] = 101;  // 因为数字范围0-100，101表示无穷大
    }
    for (int j = 1; j <= m; j++) {
        colMax[j] = -1;   // -1表示无穷小
    }

    // 遍历矩阵，找出每行的最小值和每列的最大值
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            // 更新第i行的最小值
            if (a[i][j] < rowMin[i]) {
                rowMin[i] = a[i][j];
            }
            // 更新第j列的最大值
            if (a[i][j] > colMax[j]) {
                colMax[j] = a[i][j];
            }
        }
    }

    // 统计马鞍数的个数
    int count = 0;

    // 再次遍历矩阵，检查每个数是否是马鞍数
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            // 马鞍数条件：在行上最小，在列上最大
            if (a[i][j] == rowMin[i] && a[i][j] == colMax[j]) {
                count++;
            }
        }
    }

    // 输出结果
    cout << count << endl;

    return 0;
}

