#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义矩阵大小
    int n;
    cin >> n;

    // 声明二维数组存储矩阵，最大100*100
    int a[105][105];

    // 输入矩阵数据
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            cin >> a[i][j];
        }
    }

    // 初始化主对角线最大值为一个很小的数
    int max_main = -1;  // 因为所有数都是正整数，所以用-1作为初始值

    // 遍历主对角线：行号=列号，即 i == j
    for (int i = 1; i <= n; i++) {
        if (a[i][i] > max_main) {
            max_main = a[i][i];
        }
    }

    // 初始化副对角线最小值为一个很大的数
    int min_secondary = 1001;  // 因为每个数不超过1000，所以用1001作为初始值

    // 遍历副对角线：行号+列号 = n+1，即 j = n+1-i
    for (int i = 1; i <= n; i++) {
        int j = n + 1 - i;  // 计算副对角线上的列号
        if (a[i][j] < min_secondary) {
            min_secondary = a[i][j];
        }
    }

    // 输出结果
    cout << max_main << endl;
    cout << min_secondary << endl;

    return 0;
}

