#include <bits/stdc++.h>
using namespace std;

int main() {
    // 定义矩阵的行数n和列数m
    int n, m;
    cin >> n >> m;

    // 声明一个二维数组来存储矩阵，最大为50行100列
    int a[55][105];  // 稍微开大一点，防止越界

    // 输入原始矩阵
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cin >> a[i][j];
        }
    }

    // 输出转置矩阵
    // 转置后，原来的列变成行，原来的行变成列
    // 所以外层循环遍历原来的列（0到m-1），内层循环遍历原来的行（0到n-1）
    for (int j = 0; j < m; j++) {          // j表示原来的列，现在是转置后的行
        for (int i = 0; i < n; i++) {      // i表示原来的行，现在是转置后的列
            cout << a[i][j];               // 输出a[i][j]即转置后的元素

            // 如果不是最后一个元素，输出空格
            if (i < n - 1) {
                cout << " ";
            }
        }
        cout << endl;  // 每行结束换行
    }

    return 0;
}

