    // 根据圈数计算矩阵的边长：边长为 2*n-1
    int size = 2 * n - 1;

    // 定义二维数组存储矩阵
    int a[105][105];  // 最大n=50，size最大99，开105足够

    // 从最外层到最内层，逐层填充
    // 第k层（k从0开始）的数值为 k+1
    for (int k = 0; k < n; k++) {
        // 当前层的数值
        int val = k + 1;

        // 当前层在矩阵中的范围
        // 左上角坐标 (k, k)，右下角坐标 (size-1-k, size-1-k)

        // 填充上边：行固定为k，列从k到size-1-k
        for (int j = k; j <= size - 1 - k; j++) {
            a[k][j] = val;
        }

        // 填充下边：行固定为size-1-k，列从k到size-1-k
        for (int j = k; j <= size - 1 - k; j++) {
            a[size - 1 - k][j] = val;
        }

        // 填充左边：列固定为k，行从k+1到size-2-k（避免重复填充角）
        for (int i = k + 1; i <= size - 2 - k; i++) {
            a[i][k] = val;
        }

        // 填充右边：列固定为size-1-k，行从k+1到size-2-k
        for (int i = k + 1; i <= size - 2 - k; i++) {
            a[i][size - 1 - k] = val;
        }
    }

    // 输出矩阵
    for (int i = 0; i < size; i++) {
        for (int j = 0; j < size; j++) {
            cout << a[i][j];
            // 如果不是最后一个数，输出空格
            if (j < size - 1) {
                cout << " ";
            }
        }
        // 每行结束后换行
        cout << endl;
    }

    return 0;
}

