    int n, m;
    cin >> n >> m;

    // 创建数组存储所有商品的价格
    int a[1005];  // 根据题目数据范围设定足够大的数组

    // 输入每个商品的价格
    for (int i = 0; i < n; i++) {
        cin >> a[i];
