    sort(a, a + n);

    // 计算价格总和：从最大的m个商品开始累加
    // 排序后，最大的m个商品在数组的最后m个位置
    int sum = 0;
    for (int i = n - 1; i >= n - m; i--) {
        sum += a[i];  // 累加价格最高的m件商品
    }

    // 输出结果
    cout << sum << endl;

    return 0;
}

