#include <bits/stdc++.h>
using namespace std;

int main() {
    // 输入士兵数量和船载重量
    int n, w;
    cin >> n >> w;

    // 存储所有士兵的体重
    int weight[1005];  // 假设最多1000名士兵
    for (int i = 0; i < n; i++) {
        cin >> weight[i];
    }

    // 将士兵体重从小到大排序
    // 这样我们可以优先选择体重最轻的士兵，从而装载更多人数
    sort(weight, weight + n);

    // 贪心策略：从最轻的士兵开始，依次尝试装载
    int sum = 0;      // 当前已装载士兵的总重量
    int count = 0;    // 当前已装载士兵的数量

    for (int i = 0; i < n; i++) {
        // 如果加上当前最轻的士兵不会超重，就装载他
        if (sum + weight[i] <= w) {
            sum += weight[i];
            count++;
        } else {
            // 如果超重了，说明后面的士兵更重，更不可能装载
            // 直接结束循环
            break;
        }
    }

    // 输出最多能装载的士兵数量
    cout << count << endl;

    return 0;
}

