#include <bits/stdc++.h>
using namespace std;

// 自定义比较函数：奇数在前，偶数在后；同为奇数或偶数时从小到大
bool cmp(int a, int b) {
    // 如果a是奇数，b是偶数，a应该排在b前面
    if (a % 2 == 1 && b % 2 == 0) return true;
    // 如果a是偶数，b是奇数，a应该排在b后面
    if (a % 2 == 0 && b % 2 == 1) return false;
    // 如果同为奇数或同为偶数，按从小到大排序
    return a < b;
}

int main() {
    int n;
    cin >> n;

    // 定义数组存储n个数
    int a[1005];

    // 输入n个数
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }

    // 使用sort函数和自定义比较函数进行排序
    sort(a, a + n, cmp);

    // 输出排序后的结果
    for (int i = 0; i < n; i++) {
        cout << a[i];
        if (i < n - 1) cout << " ";  // 最后一个数后面不加空格
    }
    cout << endl;

    return 0;
}

