    int year;       // 出版年份
    int month;      // 出版月份
    int text_pages; // 正文页数
    int app_pages;  // 附录页数
    int borrow;     // 借阅次数
    int sum;        // 总页数（正文+附录，整数计算）
};
book s[205];  // 数组从s[1]开始存储
// 比较函数：按时间→总页数→借阅次数→编号排序
bool cmp(book a, book b) {
    // 1. 按出版时间从新到旧
    if (a.year != b.year) {
        return a.year > b.year;
    } else if (a.month != b.month) {
        return a.month > b.month;
    }

    // 2. 时间相同，按总页数升序
    if (a.sum != b.sum) {
        return a.sum < b.sum;
    }

    // 3. 总页数相同，按借阅次数降序
    if (a.borrow != b.borrow) {
