homework.description:
现有某班学生的成绩信息需统计，每个学生包含两项信息：姓名（字符串）、分数（整数）。

请你按照以下规则对这些学生信息进行排序：

1. 首先按照分数从高到低排序;

2.若分数相同，则按照登记顺序从前到后排序;

请编写程序，登记学生信息并按照上述规则排序后输出。

homework.code:
#include <bits/stdc++.h>
using namespace std;

struct Student {
    string name;
    int score;
    int order; // 记录输入顺序
};

// 比较函数，用于排序
bool cmp(Student s1, Student s2) {
    if (s1.score != s2.score) {
        // 分数不同，按分数从高到低排
        return s1.score > s2.score;
    } else {
        // 分数相同，按输入顺序从前到后排
        return s1.order < s2.order;
    }
}

int main() {
    int n;
    cin >> n;

    Student students[60];

    for (int i = 1; i <= n; i++) {
        cin >> students[i].name >> students[i].score;
        students[i].order = i;
    }

    // 排序
    sort(students + 1, students + n + 1, cmp);

    // 输出排序后的结果
    for (int i = 1; i <= n; i++) {
        cout << students[i].name << " " << students[i].score << endl;
    }

    return 0;
}

