int main() {
    // 定义变量n表示楼梯的级数
    int n;
    cin >> n;

    // 处理特殊情况：当n为0或1时，只有1种走法
    if (n == 0 || n == 1) {
        cout << 1 << endl;
        return 0;
    }

    // 定义数组f，f[i]表示到达第i级台阶的不同走法数
    // 因为n最大可能较大，这里用long long防止溢出
    long long f[100];  // 假设n不超过100，实际可根据题目调整

    // 初始化边界条件
    f[0] = 1;  // 到达第0级（起点）有1种方式
    f[1] = 1;  // 到达第1级有1种方式（一步上一级）

    // 递推计算：f[i] = f[i-1] + f[i-2]
    // 因为到达第i级可以从第i-1级上一级，或者从第i-2级上两级
    for (int i = 2; i <= n; i++) {
        f[i] = f[i-1] + f[i-2];
    }

    // 输出到达第n级的不同走法数
    cout << f[n] << endl;

    return 0;
}

