int main() {
    int n;
    cin >> n;  // 输入台阶数

    // 处理特殊情况：当n为0或1时，只有1种走法
    if (n == 0 || n == 1) {
        cout << 1 << endl;
        return 0;
    }
    // 当n为2时，可以一次走1级走两次，或者一次走2级，共2种走法
    if (n == 2) {
        cout << 2 << endl;
        return 0;
    }

    // 定义数组f，f[i]表示到达第i级台阶的不同走法数
    // 因为n最大可能较大，用long long防止溢出
    long long f[100];  // 假设n不超过100，实际可根据题目调整

    // 初始化前三个台阶的走法数
    f[0] = 1;  // 第0级（地面）有1种走法：不动
    f[1] = 1;  // 第1级：只能一次走1级，1种走法
    f[2] = 2;  // 第2级：可以1+1或2，2种走法

    // 递推计算：从第3级开始，每一步可以来自前1级、前2级或前3级
    // 状态转移方程：f[i] = f[i-1] + f[i-2] + f[i-3]
    for (int i = 3; i <= n; i++) {
        f[i] = f[i-1] + f[i-2] + f[i-3];
    }

    cout << f[n] << endl;  // 输出到达第n级的走法数

    return 0;
}

