    cin >> n >> x;

    // 当前芒果箱数，初始为第1个城市出发时的数量
    int current = x;

    // 从第2个城市开始处理，因为第1个城市已经出发了
    // 我们需要计算离开第2个城市到第n个城市后的芒果数量
    for (int i = 2; i <= n; i++) {
        // 判断当前芒果箱数的奇偶性
        if (current % 2 == 0) {
            // 如果是偶数，卖掉一半
            current = current / 2;
        } else {
            // 如果是奇数，只卖掉1箱
            current = current - 1;
        }
    }

    // 输出离开第n个城市时的芒果箱数
    cout << current << endl;

    return 0;
}

