int main() {
    // 输入月份数n
    int n;
    cin >> n;

    // 递推求解兔子对数
    // 设f[i]表示第i个月后的兔子对数
    // 初始条件：第1个月有1对兔子（刚出生的小兔子）
    // 第2个月有1对兔子（长成大兔子，但还没生育）
    // 递推关系：f[i] = f[i-1] + f[i-2]
    // 解释：第i个月的兔子 = 第i-1个月的兔子（都存活） + 第i-2个月的兔子（每对生一对新兔子）
    // 因为兔子出生后一个月成熟，所以第i-2个月的兔子在第i个月都能生育

    // 处理n=1的特殊情况
    if (n == 1) {
        cout << 1 << endl;
        return 0;
    }

    // 定义数组存储递推结果，n最大为20，数组大小设为25足够
    int f[25];

    // 初始化前两个月的兔子对数
    f[1] = 1;  // 第1个月：1对小兔子
    f[2] = 1;  // 第2个月：1对大兔子（还没生小兔子）

    // 从第3个月开始递推计算
    for (int i = 3; i <= n; i++) {
        f[i] = f[i-1] + f[i-2];  // 斐波那契数列递推公式
    }

    // 输出第n个月后的兔子对数
    cout << f[n] << endl;

    return 0;
}

