int main() {
    // 定义变量
    int n;          // 天数
    int money = 0;  // 当前剩余零花钱，从第n天后为0开始逆向计算

    // 输入天数
    cin >> n;

    // 逆向递推：从第n天开始往前推
    // 已知第n天花完后剩余0元
    // 每天花掉当天零花钱的一半多2元
    // 设当天开始时有x元，花掉x/2+2元，剩余x - (x/2+2) = x/2 - 2元
    // 所以如果知道第二天开始时的钱，可以推出前一天开始时的钱
    // 递推公式：前一天的钱 = (当天开始的钱 + 2) * 2

    // 从第n天开始逆向计算到第1天
    for (int i = 1; i <= n; i++) {
        // 逆向递推：前一天的钱 = (当前剩余钱 + 2) * 2
        money = (money + 2) * 2;
    }

    // 输出结果
    cout << money << endl;

    return 0;
}

