    // 枚举所有可能的区间 [l, r]
    for (int l = 1; l <= n; l++) {
        for (int r = l; r <= n; r++) {
            // 区间[l, r]的和 = sum[r] - sum[l-1]
            int segSum = sum[r] - sum[l-1];

            // 判断区间和是否为偶数
            if (segSum % 2 == 0) {
                // 更新最长长度
                int len = r - l + 1;
                if (len > ans) {
                    ans = len;
                }
            }
        }
    }

    cout << ans << endl;

