#include <bits/stdc++.h>
using namespace std;

int main() {
    // 读取数组长度
    int n;
    cin >> n;

    // 读取数组元素（1-based下标）
    int a[1005];  // 题目限制n≤1000，多开一点空间
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }

    // 读取区间个数
    int m;
    cin >> m;

    // 初始化交集区间的左右端点
    // 左端点初始化为最小值1，右端点初始化为最大值n
    int L = 1, R = n;

    // 依次处理每个区间，更新交集
    for (int i = 1; i <= m; i++) {
        int Li, Ri;
        cin >> Li >> Ri;

        // 交集区间的左端点是所有Li的最大值
        if (Li > L) {
            L = Li;
        }
        // 交集区间的右端点是所有Ri的最小值
        if (Ri < R) {
            R = Ri;
        }
    }

    // 判断是否有交集
    if (L > R) {
        // 无交集，输出-1
        cout << -1 << endl;
    } else {
        // 有交集，在交集区间[L, R]内找最大值
        int maxVal = a[L];  // 初始化为区间第一个元素
        for (int i = L + 1; i <= R; i++) {
            if (a[i] > maxVal) {
                maxVal = a[i];
            }
        }
        cout << maxVal << endl;
    }

    return 0;
}

