#include <bits/stdc++.h>
using namespace std;

int main() {
    // 输入总钱数n和总鸡数m
    int n, m;
    cin >> n >> m;

    int cnt = 0;  // 方案计数器

    // 枚举公鸡的数量，公鸡5元一只
    // 公鸡最多不超过 n/5 只，也不能超过总鸡数m
    for (int x = 0; x <= n / 5 && x <= m; x++) {
        // 枚举母鸡的数量，母鸡3元一只
        // 母鸡最多不超过 (n - 5*x) / 3 只，也不能超过剩余鸡数 m - x
        for (int y = 0; y <= (n - 5 * x) / 3 && y <= m - x; y++) {
            // 小鸡的数量 = 总鸡数 - 公鸡 - 母鸡
            int z = m - x - y;

            // 小鸡必须是非负整数，且每3只小鸡1元
            // 所以小鸡数量必须是3的倍数
            if (z >= 0 && z % 3 == 0) {
                // 计算总花费：公鸡5元 + 母鸡3元 + 小鸡z/3元
                int cost = 5 * x + 3 * y + z / 3;

                // 如果总花费正好等于n元，则找到一种方案
                if (cost == n) {
                    cnt++;
                }
            }
        }
    }

    // 输出方案总数
    cout << cnt << endl;

    return 0;
}

