#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1005;  // 最大矩阵大小
int a[MAXN][MAXN];      // 存储幻方

int main() {
    int n;
    cin >> n;

    // 初始化数组为0，用于判断某个位置是否已填数
    memset(a, 0, sizeof(a));

    // 第一步：将1写在第一行的中间
    int x = 1, y = (n + 1) / 2;  // x表示行，y表示列
    a[x][y] = 1;

    // 依次填写2到n*n
    for (int k = 2; k <= n * n; k++) {
        int prev = k - 1;  // 上一个数

        // 情况1：若(K-1)在第一行但不在最后一列
        if (x == 1 && y != n) {
            x = n;      // 填在最后一行
            y = y + 1;  // 所在列的右一列
        }
        // 情况2：若(K-1)在最后一列但不在第一行
        else if (y == n && x != 1) {
            x = x - 1;  // 所在行的上一行
            y = 1;      // 填在第一列
        }
        // 情况3：若(K-1)在第一行最后一列
        else if (x == 1 && y == n) {
            x = x + 1;  // 填在正下方
            // y保持不变
        }
        // 情况4：既不在第一行，也不在最后一列
        else {
            // 检查右上方是否已填数
            if (a[x - 1][y + 1] == 0) {
                x = x - 1;  // 右上方
                y = y + 1;
            } else {
                x = x + 1;  // 正下方
                // y保持不变
            }
        }

        // 填入当前数
        a[x][y] = k;
    }

    // 输出幻方
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            cout << a[i][j];
            if (j < n) cout << " ";  // 相邻数字之间用空格隔开
        }
        cout << endl;
    }

    return 0;
}

