const int MAXN = 100005;  // 根据题目范围，n最大为10^5

int a[MAXN];      // 存储原始数列
long long sum[MAXN];  // 前缀和数组，注意用long long防止溢出

int main() {
    // 读入n
    int n;
    cin >> n;

    // 读入n个正整数，并计算前缀和
    // sum[i]表示前i个数的和，即a[1]到a[i]的和
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        sum[i] = sum[i-1] + a[i];  // 前缀和递推公式
    }

    // 读入m
    int m;
    cin >> m;

    // 处理m个区间查询
    for (int i = 1; i <= m; i++) {
        int l, r;
        cin >> l >> r;

        // 利用前缀和求区间和：区间[l,r]的和 = sum[r] - sum[l-1]
        // 因为sum[r]包含a[1]到a[r]，sum[l-1]包含a[1]到a[l-1]
        // 相减就得到a[l]到a[r]的和
        long long ans = sum[r] - sum[l-1];
        cout << ans << endl;
    }

    return 0;
}

