const int MAXN = 100005;  // 根据题目数据范围，N最大为10^5

int main() {
    // 输入N和Q
    int N, Q;
    cin >> N >> Q;

    // 定义前缀和数组，pre[i]表示前i天的收支总和
    // 使用long long防止数据溢出（a_i可能较大，累加后可能超过int范围）
    long long pre[MAXN];
    pre[0] = 0;  // 初始化前缀和，前0天和为0

    // 读入每天的收支情况，并计算前缀和
    for (int i = 1; i <= N; i++) {
        int a;
        cin >> a;
        pre[i] = pre[i-1] + a;  // 前缀和公式：前i天和 = 前i-1天和 + 第i天收支
    }

    // 处理Q次查询
    while (Q--) {
        int L, R;
        cin >> L >> R;

        // 计算区间[L, R]的总和 = 前R天和 - 前L-1天和
        long long sum = pre[R] - pre[L-1];

        // 如果总和小于0，输出"Yes"，否则输出"No"
        if (sum < 0) {
            cout << "Yes" << endl;
        } else {
            cout << "No" << endl;
        }
    }

    return 0;
}

