#include <bits/stdc++.h>
using namespace std;

int main() {
    // 读入字符串
    string s;
    cin >> s;

    int n = s.length();

    // 思路：从右向左遍历，统计每个位置后面有多少个元音
    // 对于每个辅音，它后面有多少个元音，就能组成多少对"最强音"

    // 后缀和数组，suffix[i]表示从位置i到末尾的元音个数
    // 注意：数组大小要足够大，n最大为10^5
    int suffix[100005] = {0};

    // 从右向左计算后缀和
    // 先处理最后一个字符
    char last = s[n-1];
    if (last == 'a' || last == 'e' || last == 'i' || last == 'o' || last == 'u') {
        suffix[n-1] = 1;
    } else {
        suffix[n-1] = 0;
    }

    // 从倒数第二个字符开始向前遍历
    for (int i = n-2; i >= 0; i--) {
