#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;  // 根据题目数据范围设定数组大小

int main() {
    int n;
    cin >> n;

    // a数组存储每堆金币数量，b数组存储从每堆开始可以取走的连续堆数
    int a[MAXN], b[MAXN];

    // 输入每堆金币数量
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }

    // 输入从每堆开始可以取走的连续堆数
    for (int i = 1; i <= n; i++) {
        cin >> b[i];
    }

    // 计算前缀和数组，方便快速计算区间和
    // prefix[i]表示前i堆金币的总数
    int prefix[MAXN] = {0};
    for (int i = 1; i <= n; i++) {
        prefix[i] = prefix[i-1] + a[i];
    }

    int maxGold = 0;  // 记录最多能获得的金币数

    // 枚举从每一堆开始取金币的情况
    for (int i = 1; i <= n; i++) {
        // 计算从第i堆开始，取连续b[i]堆的结束位置
        // 注意不能超过n堆，所以取min(i + b[i] - 1, n)
        int endPos = min(i + b[i] - 1, n);

        // 利用前缀和计算区间[i, endPos]的金币总数
        // prefix[endPos] - prefix[i-1] 就是区间和
        int currentGold = prefix[endPos] - prefix[i-1];

        // 更新最大值
        if (currentGold > maxGold) {
            maxGold = currentGold;
        }
    }

    // 输出最多能获得的金币数
    cout << maxGold << endl;

    return 0;
}

