#include <bits/stdc++.h>
using namespace std;

int main() {
    // 输入加油站数量
    int n;
    cin >> n;

    // 创建前缀和数组，sum[i]表示从第1个加油站到第i个加油站的距离
    // 注意：sum[1] = 0，因为第1个加油站到自身的距离为0
    int sum[100005]; // 假设n不超过100000
    sum[1] = 0;

    // 输入相邻加油站之间的距离
    for (int i = 2; i <= n; i++) {
        int dist;
        cin >> dist;
        // 计算前缀和：到第i个加油站的距离 = 到第i-1个加油站的距离 + 第i-1到第i的距离
        sum[i] = sum[i-1] + dist;
    }

    // 输入查询次数
    int q;
    cin >> q;

    // 处理每个查询
    for (int i = 0; i < q; i++) {
        int L, R;
        cin >> L >> R;

        // 确保L <= R，方便计算
        if (L > R) {
            swap(L, R);
        }

        // 使用前缀和计算距离：sum[R] - sum[L]
        // 因为sum[i]表示从第1个加油站到第i个加油站的距离
        // 所以从L到R的距离 = 从1到R的距离 - 从1到L的距离
        int ans = sum[R] - sum[L];
        cout << ans << endl;
    }

    return 0;
}

