    cin >> N >> Q;

    // 定义三个前缀和数组，分别记录品种1、2、3的前缀数量
    // prefix[i]表示前i头牛中该品种的数量
    int prefix1[MAXN] = {0};
    int prefix2[MAXN] = {0};
    int prefix3[MAXN] = {0};

    // 读入每头牛的品种，并计算前缀和
    for (int i = 1; i <= N; i++) {
        int breed;
        cin >> breed;

        // 先复制前i-1头牛的前缀和
        prefix1[i] = prefix1[i-1];
        prefix2[i] = prefix2[i-1];
        prefix3[i] = prefix3[i-1];

        // 根据当前牛的品种，增加对应品种的前缀和
        if (breed == 1) {
            prefix1[i]++;
        } else if (breed == 2) {
            prefix2[i]++;
        } else {  // breed == 3
            prefix3[i]++;
        }
    }

    // 处理Q次查询
    for (int i = 0; i < Q; i++) {
        int a, b;
        cin >> a >> b;

        // 利用前缀和计算区间[a,b]内各品种的数量
        // 区间内数量 = 前b头牛的数量 - 前a-1头牛的数量
        int count1 = prefix1[b] - prefix1[a-1];
        int count2 = prefix2[b] - prefix2[a-1];
        int count3 = prefix3[b] - prefix3[a-1];

        // 输出结果
        cout << count1 << " " << count2 << " " << count3 << endl;
    }

    return 0;
}

