const int MAXN = 1005;  // 最大地图大小

int main() {
    int n, q;
    cin >> n >> q;

    // 二维前缀和数组，pre[i][j] 表示从(1,1)到(i,j)的矩形内树的数量
    int pre[MAXN][MAXN] = {0};

    // 读入地图并构建前缀和
    for (int i = 1; i <= n; i++) {
        string line;
        cin >> line;
        for (int j = 1; j <= n; j++) {
            // 当前格子是否有树：1表示有树，0表示空地
            int tree = (line[j-1] == '*') ? 1 : 0;
            // 二维前缀和公式：当前格子的前缀和 = 左边 + 上边 - 左上角 + 当前值
            pre[i][j] = pre[i-1][j] + pre[i][j-1] - pre[i-1][j-1] + tree;
        }
    }

    // 处理每个查询
    for (int k = 1; k <= q; k++) {
        int x1, y1, x2, y2;
        cin >> x1 >> y1 >> x2 >> y2;

        // 利用二维前缀和计算矩形内树的数量
        // 公式：大矩形 - 上边矩形 - 左边矩形 + 左上角小矩形
        int ans = pre[x2][y2] - pre[x1-1][y2] - pre[x2][y1-1] + pre[x1-1][y1-1];
        cout << ans << endl;
    }

    return 0;
}

