#include <bits/stdc++.h>
using namespace std;

// 差分数组，用于高效处理区间加减操作
int diff[100005];  // 差分数组，diff[i] = a[i] - a[i-1]
int a[100005];     // 原始气温数组

int main() {
    int n, m;
    cin >> n >> m;

    // 输入初始气温
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }

    // 构建差分数组
    // diff[1] = a[1] - 0 = a[1]
    // diff[i] = a[i] - a[i-1] (i >= 2)
    diff[1] = a[1];
    for (int i = 2; i <= n; i++) {
        diff[i] = a[i] - a[i-1];
    }

    // 处理m次操作
    for (int i = 1; i <= m; i++) {
        int x, y, z;
        cin >> x >> y >> z;

        // 区间[x, y]加上z
        // 差分数组操作：diff[x] += z, diff[y+1] -= z
        diff[x] += z;
        if (y + 1 <= n) {
            diff[y+1] -= z;
        }
    }

    // 通过差分数组还原最终气温
    // a[1] = diff[1]
    // a[i] = a[i-1] + diff[i] (i >= 2)
    a[1] = diff[1];
    cout << a[1];
    for (int i = 2; i <= n; i++) {
        a[i] = a[i-1] + diff[i];
        cout << " " << a[i];
    }
    cout << endl;

    return 0;
}

