    return x.e < y.e;
}
int used[30005];//0代表没有种树，1代表种树了
int main() {
    cin>>n>>h;
    for(int i = 1;i<=h;i++){
        cin>>hs[i].b>>hs[i].e>>hs[i].t;
    }    
    sort(hs+1,hs+h+1,cmp);
    int ans = 0;// 种树数量
    for(int i = 1;i<=h;i++){
        int cnt = 0;//每个房子已经种了几棵树
        for(int j = hs[i].b; j <= hs[i].e;j++){
            cnt += used[j];
        }  
        if(hs[i].t > cnt) {//需要种树
            int need = hs[i].t - cnt;
            for(int k  = hs[i].e;k>=hs[i].b;k--){
                if(need == 0) break;
                if(used[k] == 0){
                    used[k] = 1;
                    ans++;
                    need--;
                }
            }
        }

    }
    cout<<ans;
    return 0;
}

