using namespace std;

int n, x, a[100010], ans;

int main() {
	cin >> n >> x;
	for (int i = 1; i <= n; i++)
		cin >> a[i];

	for (int i = 1; i <= n - 1; i++) {
        if (a[i] > x)  // 如果当前的大于x，就要先把这个盒子超过x的部分吃掉
        {
			ans += a[i] - x; // 吃掉超出部分
			a[i] = x;   // 更新a[i]为x个
		}
		// 处理每一组相邻的盒子 a[i] 和 a[i+1]，注意 i <= n-1
		if (a[i] + a[i + 1] > x) 
        {
			// 尽量拿每一组的后一个盒子里的糖果，可以使后边少吃一些
			int tmp = a[i] + a[i + 1] - x; // 超过 x 的糖
			ans += tmp; // 吃掉
			a[i + 1] -= tmp;    // 更新a[i+1]，把吃掉的部分减去
		}
	}
	cout << ans;
	return 0;
}

