#include <bits/stdc++.h>
using namespace std;

int main() {
    // 输入天数
    int n;
    cin >> n;

    // 输入每天的价格
    int prices[100005];  // n ≤ 10^5
    for (int i = 0; i < n; i++) {
        cin >> prices[i];
    }

    // 贪心算法思路：
    // 我们只需要在每一天记录"到目前为止的最低价格"
    // 然后计算"如果今天卖出能赚多少钱"
    // 取所有可能中的最大值就是答案

    // 初始化：第一天的最低价格就是第一天的价格
    int minPrice = prices[0];
    // 最大利润初始为0（如果一直跌，就不交易）
    int maxProfit = 0;

    // 从第二天开始遍历
    for (int i = 1; i < n; i++) {
        // 如果今天的价格比之前的最低价格还低
        // 更新最低价格（因为买得越便宜，将来卖得越赚）
        if (prices[i] < minPrice) {
            minPrice = prices[i];
        } else {
            // 否则，计算今天卖出能赚多少钱
            int profit = prices[i] - minPrice;
            // 如果比之前记录的最大利润大，就更新
            if (profit > maxProfit) {
                maxProfit = profit;
            }
        }
    }

    // 输出最大利润
    cout << maxProfit << endl;

    return 0;
}

