#include <bits/stdc++.h>
using namespace std;

// 定义奶牛结构体
struct Cow {
    int w;  // 重量
    int s;  // 力量
};

int main() {
    int n;
    cin >> n;

    Cow cows[50005];  // 存储所有奶牛
    for (int i = 0; i < n; i++) {
        cin >> cows[i].w >> cows[i].s;
    }

    // 贪心策略：按照 (重量+力量) 从小到大排序
    // 因为对于任意两头相邻的奶牛，如果上面的重量+力量更大，
    // 交换它们可以让风险值更小
    // 使用选择排序实现
    for (int i = 0; i < n - 1; i++) {
        int minIdx = i;
        for (int j = i + 1; j < n; j++) {
            // 比较 (重量+力量) 的大小
            if (cows[j].w + cows[j].s < cows[minIdx].w + cows[minIdx].s) {
                minIdx = j;
            }
        }
        // 交换位置
        if (minIdx != i) {
            Cow temp = cows[i];
            cows[i] = cows[minIdx];
            cows[minIdx] = temp;
        }
    }

    // 计算风险值
    long long sumWeight = 0;  // 当前奶牛上方所有奶牛的重量之和
    long long maxRisk = -1000000000;  // 记录最大风险值，初始化为很小的数

    for (int i = 0; i < n; i++) {
        // 当前奶牛的风险值 = 上方总重量 - 自身力量
        long long risk = sumWeight - cows[i].s;
        // 更新最大风险值
        if (risk > maxRisk) {
            maxRisk = risk;
        }
        // 将当前奶牛的重量加入总重量，供下一头奶牛计算
        sumWeight += cows[i].w;
    }

    cout << maxRisk << endl;

    return 0;
}

