#include <bits/stdc++.h>
using namespace std;

int main() {
    // 读入N和S
    int N, S;
    cin >> N >> S;

    // 读入每周的生产成本和需求量
    int A[10005], B[10005];
    for (int i = 1; i <= N; i++) {
        cin >> A[i] >> B[i];
    }

    // 贪心策略：对于第i周，我们有两种选择：
    // 1. 本周生产本周交付，成本为 A[i] * B[i]
    // 2. 从之前某周生产并存储到本周交付，成本为 (之前某周的生产成本 + 存储周数 * S) * B[i]
    // 我们只需要维护一个"当前最优生产成本"，即 min(之前所有周的生产成本 + 存储到本周的费用)
    // 这个最优成本会随着周数增加而更新

    long long totalCost = 0;  // 总成本，用long long防止溢出
    int minCost = A[1];       // 当前最优生产成本（已经考虑了存储费用）

    for (int i = 1; i <= N; i++) {
        // 更新当前最优生产成本：要么继续用之前的，要么用本周的生产成本
        // 注意：如果本周生产成本比之前最优成本+存储费还低，就改用本周生产
        if (A[i] < minCost + S) {
            minCost = A[i];
        } else {
            // 否则，最优成本就是之前的最优成本加上本周的存储费
            minCost = minCost + S;
        }

        // 用当前最优成本生产本周需要的酸奶
        totalCost += (long long)minCost * B[i];
    }

    cout << totalCost << endl;

    return 0;
}

