// 比较函数：判断两个数字拼接后哪个更大
// 如果 a+b > b+a，则 a 应该排在 b 前面
bool cmp(string a, string b) {
    return a + b > b + a;
}

int main() {
    int n;
    cin >> n;

    // 读入n个数字，用字符串存储方便拼接比较
    string a[25]; // n <= 20，数组大小开大一点
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }

    // 使用冒泡排序（因为题目要求只能用P56及之前的排序算法）
    // 按照自定义的比较规则排序
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - 1 - i; j++) {
            // 如果a[j]应该排在a[j+1]后面，则交换
            if (cmp(a[j+1], a[j])) {
                swap(a[j], a[j+1]);
            }
        }
    }

    // 拼接所有数字
    string ans = "";
    for (int i = 0; i < n; i++) {
        ans += a[i];
    }

    // 处理特殊情况：如果所有数字都是0，则输出0
    // 检查第一个字符是否为'0'，如果是则说明所有数字都是0
    if (ans[0] == '0') {
        cout << "0" << endl;
    } else {
        cout << ans << endl;
    }

    return 0;
}

