#include <bits/stdc++.h>
using namespace std;

// 定义大臣结构体，存储左右手的数字
struct Minister {
    int left;   // 左手数字
    int right;  // 右手数字
};

// 自定义排序规则：按照左手*右手从小到大排序
// 这是贪心策略的核心：让左右手乘积小的大臣排在前面
bool cmp(Minister a, Minister b) {
    return a.left * a.right < b.left * b.right;
}

int main() {
    int n;
    cin >> n;

    // 读取国王的左右手数字
    int kingLeft, kingRight;
    cin >> kingLeft >> kingRight;

    // 创建大臣数组
    Minister ministers[1005];

    // 读取每个大臣的左右手数字
    for (int i = 0; i < n; i++) {
        cin >> ministers[i].left >> ministers[i].right;
    }

    // 使用冒泡排序按照左右手乘积从小到大排序
    // 因为题目限制只能使用选择排序、冒泡排序、插入排序、计数排序
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - 1 - i; j++) {
            if (ministers[j].left * ministers[j].right > 
                ministers[j + 1].left * ministers[j + 1].right) {
                // 交换两个大臣的位置
                Minister temp = ministers[j];
                ministers[j] = ministers[j + 1];
                ministers[j + 1] = temp;
            }
        }
    }

    // 计算每个大臣获得的金币数，找出最大值
    // 当前乘积记录前面所有人的左手数字的乘积
    long long currentProduct = kingLeft;  // 初始为国王的左手数字
    long long maxGold = 0;  // 记录最大金币数

    for (int i = 0; i < n; i++) {
        // 当前大臣获得的金币 = 前面所有人左手乘积 / 自己的右手数字
        long long gold = currentProduct / ministers[i].right;

        // 更新最大金币数
        if (gold > maxGold) {
            maxGold = gold;
        }

        // 更新乘积，乘上当前大臣的左手数字
        currentProduct = currentProduct * ministers[i].left;
    }

    cout << maxGold << endl;

    return 0;
}

