#include <bits/stdc++.h>
using namespace std;

// 定义任务结构体，存储第一次经验和后续每次经验
struct Task {
    int first;   // 第一次完成获得的经验值 a_i
    int repeat;  // 之后每次完成获得的经验值 b_i
};

int main() {
    int n, k;
    cin >> n >> k;

    // 读入第一次完成获得的经验值
    int a[1005];  // 假设n不超过1000
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }

    // 读入后续每次完成获得的经验值
    int b[1005];
    for (int i = 1; i <= n; i++) {
        cin >> b[i];
    }

    // 创建任务数组
    Task tasks[1005];
    for (int i = 1; i <= n; i++) {
        tasks[i].first = a[i];
        tasks[i].repeat = b[i];
    }

    // 贪心策略：每次选择能获得最多经验值的任务
    // 但要注意，第i个任务必须在前i-1个任务都至少完成一次后才能做
    // 所以我们需要按顺序解锁任务

    long long totalExp = 0;  // 总经验值，用long long防止溢出
    int completed[1005] = {0};  // 记录每个任务已经完成的次数
    int maxUnlocked = 1;  // 当前已解锁的最大任务编号

    // 进行k次任务
    for (int step = 1; step <= k; step++) {
        // 检查是否有新任务可以解锁
        // 如果前maxUnlocked个任务都至少完成了一次，就可以解锁下一个任务
        bool canUnlock = true;
        for (int i = 1; i <= maxUnlocked; i++) {
            if (completed[i] == 0) {
                canUnlock = false;
                break;
            }
        }
        if (canUnlock && maxUnlocked < n) {
            maxUnlocked++;
        }

        // 在已解锁的任务中，选择能获得最多经验值的任务
        int bestTask = -1;
        long long bestExp = -1;

        for (int i = 1; i <= maxUnlocked; i++) {
            long long exp;
            if (completed[i] == 0) {
                // 第一次完成这个任务
                exp = tasks[i].first;
            } else {
                // 后续完成这个任务
                exp = tasks[i].repeat;
            }

            if (exp > bestExp) {
                bestExp = exp;
                bestTask = i;
            }
        }

        // 完成选中的任务
        completed[bestTask]++;
        totalExp += bestExp;
    }

    cout << totalExp << endl;

    return 0;
}

