    for (int i = 0; i < n; i++) {
        cin >> a[i].height >> a[i].weight;
    }

    // 冒泡排序思想：每次交换相邻元素，统计交换次数
    // 因为只能交换相邻位置，最少交换次数就是逆序对的数量
    // 我们使用冒泡排序来统计逆序对
    int ans = 0;

    // 冒泡排序，从前往后比较相邻元素
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - 1 - i; j++) {
            // 判断是否需要交换：如果前面的同学应该排在后面，则需要交换
            bool needSwap = false;

            // 比较规则：先按身高从高到低，身高相同按体重从重到轻
            if (a[j].height < a[j + 1].height) {
                // 前面的身高更矮，应该排到后面去，需要交换
