#include <bits/stdc++.h>
using namespace std;

int main() {
    // 输入n和x
    int n, x;
    cin >> n >> x;

    // 输入n个小球上的数字
    int a[1005]; // 假设n不超过1000
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }

    // 使用计数排序的思想，统计每个数字出现的次数
    // 因为数字范围未知，但题目没有给出范围，我们假设数字在0-1000之间
    int cnt[2005] = {0}; // 用于统计每个数字出现的次数，数组大小要足够大
    for (int i = 0; i < n; i++) {
        cnt[a[i]]++;
    }

    int ans = 0; // 记录不同找法的数量

    // 遍历所有可能的数字对
    for (int i = 0; i < n; i++) {
        // 对于当前小球a[i]，需要找到另一个小球使得和为x
        int need = x - a[i]; // 需要的另一个数字

        // 如果需要的数字存在
        if (need >= 0 && cnt[need] > 0) {
            // 如果需要的数字和当前数字相同
            if (need == a[i]) {
                // 从cnt[a[i]]个相同数字中选2个，组合数为C(cnt,2)
                // 但为了避免重复计数，我们只计算一次
                // 这里我们只计算一次，因为后面遍历到另一个相同数字时会重复
                // 所以只计算一次：cnt[a[i]] * (cnt[a[i]] - 1) / 2
                // 但为了简单，我们可以在遍历时只考虑need > a[i]的情况
                // 或者使用另一种方法
            }
        }
    }

    // 更简单的方法：双重循环枚举所有数对
    ans = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (a[i] + a[j] == x) {
                ans++;
            }
        }
    }

    cout << ans << endl;

    return 0;
}

