#include <bits/stdc++.h>
using namespace std;

// 求最大公约数（辗转相除法）
int gcd(int x, int y) {
    while (y != 0) {
        int temp = y;
        y = x % y;
        x = temp;
    }
    return x;
}

int main() {
    int a, b;
    cin >> a >> b;

    // 找出较小值和较大值
    int smaller = a < b ? a : b;
    int larger = a > b ? a : b;

    // 计算最大公约数，用于约分
    int g = gcd(smaller, larger);

    // 输出约分后的最简分数
    cout << smaller / g << "/" << larger / g << endl;

    return 0;
}

