#include <bits/stdc++.h>
using namespace std;

// 求最大公约数（辗转相除法）
int gcd(int x, int y) {
    while (y != 0) {
        int temp = y;
        y = x % y;
        x = temp;
    }
    return x;
}

// 求最小公倍数
int lcm(int x, int y) {
    // 先除以最大公约数再相乘，防止溢出
    return x / gcd(x, y) * y;
}

int main() {
    int a, b, c;
    cin >> a >> b >> c;

    // 先求前两个数的最小公倍数
    int temp = lcm(a, b);
    // 再和第三个数求最小公倍数
    int ans = lcm(temp, c);

    cout << ans << endl;

    return 0;
}

