#include <bits/stdc++.h>
using namespace std;

// 求最大公约数（辗转相除法）
int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int m, n;
    cin >> m >> n;

    // 如果n不能被m整除，则不存在这样的x,y
    if (n % m != 0) {
        cout << 0 << endl;
        return 0;
    }

    // 令k = n/m，则x = m * a, y = m * b
    // 其中a和b互质，且a * b = k
    int k = n / m;
    int count = 0;

    // 枚举k的所有因子a
    // 注意：a和b都是正整数，且a * b = k
    // 我们枚举a从1到sqrt(k)
    for (int a = 1; a * a <= k; a++) {
        if (k % a == 0) {
            int b = k / a;
            // 检查a和b是否互质
            if (gcd(a, b) == 1) {
                // 找到一对互质的因子(a,b)
                // 注意：当a != b时，(a,b)和(b,a)是两组不同的解
                if (a == b) {
                    count++;  // a=b时只有一组解
                } else {
                    count += 2;  // a!=b时有两组解：(a,b)和(b,a)
                }
            }
        }
    }

    cout << count << endl;
    return 0;
}

