// 求两个数的最大公约数（辗转相除法）
int gcd(int a, int b) {
    while (b != 0) {
        int temp = a % b;  // 余数
        a = b;             // 更新a为原来的b
        b = temp;          // 更新b为余数
    }
    return a;  // 当b为0时，a就是最大公约数
}

int main() {
    int x, y, z;
    cin >> x >> y >> z;

    // 先求x和y的最大公约数
    int g = gcd(x, y);
    // 再求g和z的最大公约数，得到三个数的最大公约数
    g = gcd(g, z);

    cout << g << endl;
    return 0;
}

