// 求最大公约数（辗转相除法）
int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int a, b, c;
    cin >> a >> b >> c;

    // 找出最小的边和最大的边
    int min_side = a;  // 假设a是最小的
    if (b < min_side) min_side = b;
    if (c < min_side) min_side = c;

    int max_side = a;  // 假设a是最大的
    if (b > max_side) max_side = b;
    if (c > max_side) max_side = c;

    // 较小锐角的正弦值 = 最小的边 / 最大的边
    int numerator = min_side;   // 分子
    int denominator = max_side; // 分母

    // 约分：分子分母同时除以它们的最大公约数
    int g = gcd(numerator, denominator);
    numerator /= g;
    denominator /= g;

    // 输出分数格式
    cout << numerator << "/" << denominator << endl;

    return 0;
}

