#include <bits/stdc++.h>
using namespace std;

// 求最大公约数（辗转相除法）
long long gcd(long long a, long long b) {
    while (b != 0) {
        long long temp = a % b;
        a = b;
        b = temp;
    }
    return a;
}

// 求最小公倍数
long long lcm(long long a, long long b) {
    return a / gcd(a, b) * b;  // 先除后乘防止溢出
}

int main() {
    int T;
    cin >> T;

    while (T--) {
        long long n;
        cin >> n;

        // 思路：要使两个不超过n的正整数的最小公倍数最大
        // 最优策略是选择n和n-1（因为相邻两个数互质，lcm就是它们的乘积）
        // 或者选择n和n-2（当n为偶数时，n和n-1的乘积可能不是最大）

        long long ans = 0;

        // 情况1：选择n和n-1（相邻两个数一定互质）
        if (n >= 2) {
            ans = max(ans, lcm(n, n-1));
        }

        // 情况2：选择n-1和n-2（相邻两个数一定互质）
        if (n >= 3) {
            ans = max(ans, lcm(n-1, n-2));
        }

        // 情况3：选择n和n-2（当n为奇数时，n和n-2的最大公约数为1，即互质）
        if (n >= 3) {
            ans = max(ans, lcm(n, n-2));
        }

        // 特殊情况：n=1时，只能选1和1
        if (n == 1) {
            ans = 1;
        }

        cout << ans << endl;
    }

    return 0;
}

