#include <bits/stdc++.h>
using namespace std;

// 求最大公约数（辗转相除法）
int gcd(int a, int b) {
    while (b != 0) {
        int temp = a % b;
        a = b;
        b = temp;
    }
    return a;
}

int main() {
    int A, B, L;
    cin >> A >> B >> L;

    // bestA和bestB用于记录当前找到的最优解
    int bestA = 1, bestB = 1;
    // 初始化最优比例为一个很大的数
    double bestDiff = 1e9;

    // 枚举所有可能的A'（1到L）
    for (int a = 1; a <= L; a++) {
        // 枚举所有可能的B'（1到L）
        for (int b = 1; b <= L; b++) {
            // 检查A'和B'是否互质
            if (gcd(a, b) != 1) {
                continue;
            }

            // 检查A'/B' >= A/B是否成立
            // 为了避免浮点数精度问题，用乘法比较：a * B >= A * b
            if (a * B < A * b) {
                continue;
            }

            // 计算当前比例与真实比例的差值
            double curDiff = (double)a / b - (double)A / B;

            // 如果当前差值更小，更新最优解
            if (curDiff < bestDiff) {
                bestDiff = curDiff;
                bestA = a;
                bestB = b;
            }
        }
    }

    // 输出结果
    cout << bestA << " " << bestB << endl;

    return 0;
}

