    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int n;  // 数据组数
    cin >> n;

    while (n--) {
        int ax, ay;  // 猎人位置
        int bx, by;  // 兔八哥位置
        cin >> ax >> ay >> bx >> by;

        // 计算两个位置在x方向和y方向上的距离差
        int dx = abs(ax - bx);
        int dy = abs(ay - by);

        // 如果两个位置重合，猎人可以直接看到兔子
        if (dx == 0 && dy == 0) {
            cout << "no" << endl;
            continue;
        }

        // 判断连线上是否有其他果树
        // 如果dx和dy的最大公约数为1，说明连线上没有其他整数点（果树）
        // 即猎人可以直接看到兔子，兔子不安全
        if (gcd(dx, dy) == 1) {
            cout << "no" << endl;  // 不安全
        } else {
            cout << "yes" << endl; // 安全
        }
    }

    return 0;
}

