#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;  // 输入待分解的正整数

    // 从最小的质因子2开始尝试
    // 因为n ≤ 10^9，所以i*i不会超过int范围，用int即可
    for (int i = 2; i * i <= n; i++) {
        // 当i能整除n时，i就是n的一个质因子
        // 注意：这里i一定是质数，因为合数因子会被更小的质因子先分解掉
        while (n % i == 0) {
            cout << i << " ";  // 输出这个质因子
            n = n / i;         // 将n除以这个质因子，继续分解
        }
    }

    // 如果最后n大于1，说明n本身是一个质数（或者剩余一个大于sqrt(原n)的质因子）
    // 例如：n=17，循环结束后n=17>1，输出17
    if (n > 1) {
        cout << n << " ";
    }

    cout << endl;  // 输出换行
    return 0;
}

