using namespace std;

int main() {
    int n;
    cin >> n;

    // 思路：求n的约数个数
    // 因为分配方式就是n的约数个数（分给多少人）
    // 例如n=12，约数有1,2,3,4,6,12共6个

    int ans = 0;

    // 只需要枚举到sqrt(n)即可
    // 因为约数是成对出现的：如果i是n的约数，那么n/i也是n的约数
    for (int i = 1; i * i <= n; i++) {
        if (n % i == 0) {
            // i是n的约数
            ans++;
            // 如果i != n/i，说明n/i是另一个不同的约数
            if (i != n / i) {
                ans++;
            }
        }
    }

    cout << ans << endl;

    return 0;
}

