#include <bits/stdc++.h>
using namespace std;

// 判断一个数是否为质数
bool isPrime(int n) {
    if (n < 2) return false;          // 小于2不是质数
    if (n == 2) return true;          // 2是质数
    if (n % 2 == 0) return false;     // 偶数不是质数（除了2）

    // 从3开始检查奇数因子，只需要检查到sqrt(n)
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return false;
    }
    return true;
}

int main() {
    int N;
    cin >> N;                         // 输入一个偶数N

    // 从最小的质数2开始尝试
    // 因为要输出A最小的组合，所以从最小的质数开始找
    for (int A = 2; A <= N / 2; A++) {
        // 检查A是否为质数
        if (!isPrime(A)) continue;

        // 计算B = N - A
        int B = N - A;

        // 检查B是否为质数
        if (isPrime(B)) {
            // 找到满足条件的组合，输出并结束程序
            cout << A << " " << B << endl;
            return 0;
        }
    }

    return 0;
}

