#include <bits/stdc++.h>
using namespace std;

// 判断一个数是否为质数
bool isPrime(int n) {
    if (n < 2) return false;  // 小于2不是质数
    // 只需要检查到sqrt(n)即可
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) return false;  // 能被整除则不是质数
    }
    return true;
}

// 将一个整数逆序
int reverseNum(int n) {
    int rev = 0;
    while (n > 0) {
        rev = rev * 10 + n % 10;  // 取出最后一位，加到rev末尾
        n /= 10;                  // 去掉最后一位
    }
    return rev;
}

int main() {
    int L, R;
    cin >> L >> R;

    // 先用埃氏筛法预处理出[1,R]范围内的所有质数
    // 因为R最大为200000，用bool数组即可
    vector<bool> isPrimeArr(R + 1, true);
    isPrimeArr[0] = isPrimeArr[1] = false;  // 0和1不是质数

    // 埃氏筛法核心：从2开始，将每个质数的倍数标记为合数
    for (int i = 2; i * i <= R; i++) {
        if (isPrimeArr[i]) {  // 如果i是质数
            // 从i*i开始标记，因为i*2到i*(i-1)已经被更小的质数标记过了
            for (int j = i * i; j <= R; j += i) {
                isPrimeArr[j] = false;
            }
        }
    }

    int count = 0;  // 统计真质数的个数

    // 遍历[L,R]区间内的每个数
    for (int i = L; i <= R; i++) {
        // 条件1：i本身是质数
        // 条件2：i逆序后的数也是质数
        if (isPrimeArr[i]) {
            int rev = reverseNum(i);  // 计算逆序数
            // 逆序数可能超过R，但我们需要判断它是否为质数
            // 如果逆序数大于R，需要用普通质数判断函数
            if (rev <= R) {
                // 逆序数在范围内，直接用筛法结果判断
                if (isPrimeArr[rev]) {
                    count++;
                }
            } else {
                // 逆序数超出范围，用普通质数判断函数
                if (isPrime(rev)) {
                    count++;
                }
            }
        }
    }

    cout << count << endl;
    return 0;
}

