#include <bits/stdc++.h>
using namespace std;

// 质数筛法：找出1到n之间的所有质数
// 使用埃氏筛法，时间复杂度O(n log log n)
vector<int> getPrimes(int n) {
    vector<bool> isPrime(n + 1, true);  // 标记数组，true表示是质数
    vector<int> primes;                 // 存储质数

    // 0和1不是质数
    isPrime[0] = isPrime[1] = false;

    // 从2开始筛
    for (int i = 2; i <= n; i++) {
        if (isPrime[i]) {
            primes.push_back(i);  // i是质数，加入列表
            // 将i的倍数标记为合数
            for (int j = i * i; j <= n; j += i) {
                isPrime[j] = false;
            }
        }
    }
    return primes;
}

// 计算n!中质因子p的个数
// 公式：n!中p的个数 = n/p + n/p^2 + n/p^3 + ...
int countFactor(int n, int p) {
    int count = 0;
    int power = p;  // p的幂次
    while (power <= n) {
        count += n / power;  // 加上n/p^k的整数部分
        // 注意：这里可能溢出，但n≤10000，p^2可能超过int范围
        // 所以用除法判断是否还能继续乘
        if (power > n / p) break;  // 防止溢出，如果乘p会超过n就停止
        power *= p;
    }
    return count;
}

int main() {
    int n;
    cin >> n;

    // 获取1到n之间的所有质数
    vector<int> primes = getPrimes(n);

    // 对每个质数，计算它在n!中出现的次数
    for (int i = 0; i < primes.size(); i++) {
        int p = primes[i];
        int cnt = countFactor(n, p);
        // 只有出现次数大于0才输出
        if (cnt > 0) {
            cout << p << " " << cnt << endl;
        }
    }

    return 0;
}

