// 求约数个数的公式：
// 如果 N = p1^c1 * p2^c2 * ... * pk^ck
// 那么约数个数 = (c1+1) * (c2+1) * ... * (ck+1)
// 本题要求所有数乘积的约数个数，所以需要统计所有质因子的总指数

const int MOD = 1e9 + 7;

int main() {
    int n;
    cin >> n;

    // 用数组记录每个质因数的指数，因为a_i最大2e9，质因数个数有限
    // 2e9 < 2^31，所以质因数个数不会太多
    int primes[100000];  // 存储质因数
    int cnt[100000];     // 存储对应质因数的指数
    int prime_cnt = 0;   // 质因数的种类数

    for (int i = 0; i < n; i++) {
        int x;
        cin >> x;

        // 对每个数分解质因数
        // 从2开始试除，只需要试到sqrt(x)
        for (int j = 2; j * j <= x; j++) {
            if (x % j == 0) {
                // 找到一个新的质因数j
                int exp = 0;
                while (x % j == 0) {
                    x /= j;
                    exp++;
                }

                // 检查这个质因数是否已经出现过
                bool found = false;
                for (int k = 0; k < prime_cnt; k++) {
                    if (primes[k] == j) {
                        cnt[k] += exp;
                        found = true;
                        break;
                    }
                }
                // 如果是新的质因数，添加到数组中
                if (!found) {
                    primes[prime_cnt] = j;
                    cnt[prime_cnt] = exp;
                    prime_cnt++;
                }
            }
        }

        // 如果x>1，说明x本身是一个质因数
        if (x > 1) {
            bool found = false;
            for (int k = 0; k < prime_cnt; k++) {
                if (primes[k] == x) {
                    cnt[k]++;
                    found = true;
                    break;
                }
            }
            if (!found) {
                primes[prime_cnt] = x;
                cnt[prime_cnt] = 1;
                prime_cnt++;
            }
        }
    }

    // 根据公式计算约数个数：所有(指数+1)的乘积
    long long ans = 1;
    for (int i = 0; i < prime_cnt; i++) {
        ans = ans * (cnt[i] + 1) % MOD;
    }

    cout << ans << endl;

    return 0;
}

