#include <bits/stdc++.h>
using namespace std;

// 质数判断函数（试除法）
bool isPrime(int n) {
    if (n < 2) return false;  // 1不是质数
    if (n == 2) return true;  // 2是质数
    if (n % 2 == 0) return false;  // 偶数不是质数（除了2）

    // 从3开始，只检查奇数因子，到sqrt(n)为止
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return false;
    }
    return true;
}

int main() {
    int N;
    cin >> N;

    int count = 0;  // 质数个数计数器

    // 遍历1到N，判断每个数是否为质数
    for (int i = 1; i <= N; i++) {
        if (isPrime(i)) {
            count++;
        }
    }

    cout << count << endl;
    return 0;
}

