#include <bits/stdc++.h>
using namespace std;

// 判断一个数是否为质数
bool isPrime(int x) {
    if (x < 2) return false;
    // 只需要检查到sqrt(x)即可
    for (int i = 2; i * i <= x; i++) {
        if (x % i == 0) return false;
    }
    return true;
}

// 判断一个数是否为回文数
bool isPalindrome(int x) {
    int original = x;
    int reversed = 0;
    // 将数字反转
    while (x > 0) {
        reversed = reversed * 10 + x % 10;
        x /= 10;
    }
    // 如果反转后与原数相等，则是回文数
    return original == reversed;
}

int main() {
    int a, b;
    cin >> a >> b;

    // 优化：如果b大于10000000（一千万），实际上最大的回文质数不会超过一千万
    // 因为8位的回文数都能被11整除（除了11本身），所以一亿范围内最大的回文质数不超过一千万
    if (b > 10000000) {
        b = 10000000;
    }

    // 遍历区间[a, b]中的所有数
    for (int i = a; i <= b; i++) {
        // 先判断回文数，因为回文数判断更快，可以提前过滤掉大部分数
        if (isPalindrome(i)) {
            // 如果是回文数，再判断是否为质数
            if (isPrime(i)) {
                cout << i << endl;
            }
        }
    }

    return 0;
}

