#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;

    int maxNum = 0;      // 记录约数最多的数
    int maxCnt = 0;      // 记录最多的约数个数

    // 枚举1到n中的每个数
    for (int i = 1; i <= n; i++) {
        int cnt = 0;     // 记录当前数i的约数个数

        // 枚举可能的约数，从1到sqrt(i)即可
        // 因为如果d是i的约数，那么i/d也是i的约数
        for (int d = 1; d * d <= i; d++) {
            if (i % d == 0) {
                cnt++;   // d是约数
                if (d * d != i) {
                    cnt++;   // i/d也是约数，且与d不同
                }
            }
        }

        // 如果当前数的约数个数比已知的最大值大，则更新
        // 由于是从小到大枚举，所以当约数个数相等时，不会更新
        // 这样就保证了输出最小的那个数
        if (cnt > maxCnt) {
            maxCnt = cnt;
            maxNum = i;
        }
    }

    cout << maxNum << " " << maxCnt << endl;

    return 0;
}

