#include <bits/stdc++.h>
using namespace std;

// 二分查找函数：在升序数组a中查找最接近target的值
// 如果有多个距离相同，返回较小的那个
int findClosest(int a[], int n, int target) {
    int left = 0, right = n - 1;

    // 特殊情况：如果目标小于等于第一个数，直接返回第一个数
    if (target <= a[0]) return a[0];
    // 如果目标大于等于最后一个数，直接返回最后一个数
    if (target >= a[n-1]) return a[n-1];

    // 二分查找，找到target应该插入的位置
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (a[mid] == target) {
            return a[mid];  // 找到完全相等的值，直接返回
        } else if (a[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    // 此时left是第一个大于target的位置，right是最后一个小于target的位置
    // 比较a[right]和a[left]哪个更接近target
    int leftDiff = target - a[right];   // 左边差值（正数）
    int rightDiff = a[left] - target;   // 右边差值（正数）

    // 如果左边更接近，或者两边距离相等（取较小的），返回左边
    if (leftDiff <= rightDiff) {
        return a[right];
    } else {
        return a[left];
    }
}

