    // 特殊情况：如果x小于等于最小值，直接返回最小值
    if (x <= a[0]) return a[0];
    // 如果x大于等于最大值，直接返回最大值
    if (x >= a[n-1]) return a[n-1];

    // 二分查找第一个大于等于x的位置
    int left = 0, right = n - 1;
    while (left < right) {
        int mid = (left + right) / 2;
        if (a[mid] >= x) {
            right = mid;
        } else {
            left = mid + 1;
