// 二分查找函数：在有序数组a中查找最接近x的值
// 如果存在多个同样接近的值，返回较小的那个
int findClosest(int a[], int n, int x) {
    // 特殊情况：如果x小于等于最小值，直接返回最小值
    if (x <= a[0]) return a[0];
    // 如果x大于等于最大值，直接返回最大值
    if (x >= a[n-1]) return a[n-1];

    // 二分查找第一个大于等于x的位置
    int left = 0, right = n - 1;
    while (left < right) {
        int mid = (left + right) / 2;
        if (a[mid] >= x) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }

    // left是第一个大于等于x的位置
    // 比较a[left]和a[left-1]哪个更接近x
    if (a[left] - x < x - a[left-1]) {
        return a[left];  // a[left]更接近
    } else {
        return a[left-1];  // a[left-1]更接近或相等（相等时返回较小的）
    }
}

