#include <bits/stdc++.h>
using namespace std;

// 定义物资结构体，包含种类和单价
struct Item {
    int type;      // 种类
    double price;  // 单价
};

// 比较函数，用于sort排序：先按种类从小到大，种类相同按单价从小到大
bool cmp(Item a, Item b) {
    if (a.type != b.type) {
        return a.type < b.type;
    }
    return a.price < b.price;
}

int main() {
    int n;
    cin >> n;

    // 创建vector存储所有物资
    vector<Item> items(n);

    // 读入n件物资
    for (int i = 0; i < n; i++) {
        cin >> items[i].type >> items[i].price;
    }

    // 按种类和单价排序
    sort(items.begin(), items.end(), cmp);

    // 按种类分组输出
    int curType = 1;  // 当前要输出的种类，从1开始
    int idx = 0;      // 当前遍历到的位置

    // 遍历所有可能的种类（1到n）
    while (curType <= n) {
        // 检查当前种类是否有物资
        if (idx < n && items[idx].type == curType) {
            // 输出当前种类的所有物资
            bool first = true;
            while (idx < n && items[idx].type == curType) {
                if (!first) {
                    cout << " ";
                }
                // 固定输出两位小数
                cout << fixed << setprecision(2) << items[idx].price;
                first = false;
                idx++;
            }
            cout << endl;
        } else {
            // 当前种类没有物资，输出空行
            cout << endl;
        }
        curType++;
    }

    return 0;
}

