#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    // 使用队列模拟约瑟夫环
    queue<int> q;

    // 将1到n号人依次入队
    for (int i = 1; i <= n; i++) {
        q.push(i);
    }

    // 当前报数的计数
    int count = 0;

    // 当队列不为空时，继续出圈过程
    while (!q.empty()) {
        // 取出队首的人
        int person = q.front();
        q.pop();

        // 报数加1
        count++;

        // 如果报数到m，这个人出圈
        if (count == m) {
            // 输出出圈人的编号
            cout << person;
            // 如果不是最后一个出圈的人，输出空格
            if (!q.empty()) {
                cout << " ";
            }
            // 重置报数计数器
            count = 0;
        } else {
            // 报数没到m，这个人重新回到队尾，继续下一轮报数
            q.push(person);
        }
    }

    cout << endl;
    return 0;
}

