const int MAXN = 1005;  // 最大城市数量

int main() {
    int N, E;
    cin >> N >> E;

    // 使用vector数组存储每个城市的邻接城市
    // adj[i]表示城市i连接的所有城市
    vector<int> adj[MAXN];

    // 读取E条道路信息
    for (int i = 0; i < E; i++) {
        int u, v;
        cin >> u >> v;
        // 因为是双向道路，所以两个城市互相连接
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // 按照城市编号1~N的顺序输出
    for (int i = 1; i <= N; i++) {
        // 如果当前城市没有相连的城市，输出空行
        if (adj[i].empty()) {
            cout << endl;
            continue;
        }

        // 对当前城市的邻接城市进行排序（从小到大）
        // 使用冒泡排序，因为不能使用algorithm库中的sort
        int len = adj[i].size();
        for (int j = 0; j < len - 1; j++) {
            for (int k = 0; k < len - 1 - j; k++) {
                if (adj[i][k] > adj[i][k + 1]) {
                    // 交换两个相邻元素
                    int temp = adj[i][k];
                    adj[i][k] = adj[i][k + 1];
                    adj[i][k + 1] = temp;
                }
            }
        }

        // 输出该城市的所有邻接城市
        for (int j = 0; j < len; j++) {
            cout << adj[i][j];
            if (j < len - 1) {
                cout << " ";  // 最后一个数字后面不加空格
            }
        }
        cout << endl;  // 每个城市输出一行
    }

    return 0;
}

