#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;  // 输入指令条数和队列最大容量

    queue<int> q;   // 订单队列，存储顾客编号
    int nextId = 1; // 下一个可分配的顾客编号，从1开始递增

    for (int i = 0; i < n; i++) {
        string op;
        cin >> op;  // 读取指令类型

        if (op == "push") {
            // 顾客下单指令
            if (q.size() == m) {
                // 队列已满，订餐失败
                cout << "fail" << endl;
            } else {
                // 分配编号并加入队列
                cout << nextId << endl;
                q.push(nextId);
                nextId++;  // 编号递增
            }
        } else if (op == "pop") {
            // 厨师出餐指令
            if (q.empty()) {
                // 队列为空，无法出餐（题目保证不会出现这种情况）
                // 但为了代码健壮性，可以输出空行或不做处理
                cout << endl;
            } else {
                // 输出队首顾客编号并出队
                cout << q.front() << endl;
                q.pop();
            }
        } else if (op == "check") {
            // 查询进度指令
            int x;
            cin >> x;  // 读取要查询的顾客编号

            // 计算在x之前的订单数量
            // 方法：遍历队列，统计编号小于x的订单数
            // 注意：不能直接访问队列内部元素，需要临时复制队列
            queue<int> temp = q;  // 复制队列，避免破坏原队列
            int count = 0;
            while (!temp.empty()) {
                if (temp.front() < x) {
                    count++;  // 统计在x之前的订单
                }
                temp.pop();
            }
            cout << count << endl;
        }
    }

    return 0;
}

