#include <bits/stdc++.h>
using namespace std;

int main() {
    int M, N; // M:内存容量, N:文章长度
    cin >> M >> N;

    queue<int> q; // 队列模拟内存，存放单词编号
    bool inMemory[1005] = {false}; // 标记单词是否在内存中，单词编号不超过1000
    int count = 0; // 查词典次数

    for (int i = 0; i < N; i++) {
        int word;
        cin >> word; // 读取当前单词

        // 如果单词不在内存中，需要查词典
        if (!inMemory[word]) {
            count++; // 查词典次数+1

            // 如果内存已满（队列长度等于M），需要移除最早进入的单词
            if (q.size() == M) {
                int frontWord = q.front(); // 获取最早进入的单词
                q.pop(); // 从队列中移除
                inMemory[frontWord] = false; // 标记该单词不在内存中
            }

            // 将新单词加入内存
            q.push(word); // 加入队列末尾
            inMemory[word] = true; // 标记该单词在内存中
        }
        // 如果单词已经在内存中，直接跳过，不需要查词典
    }

    cout << count << endl; // 输出查词典次数
    return 0;
}

